export const AOL_200 = [
  // ==================== EASY (60) ====================
  {id:"aol-001",d:"easy",t:"TMAE Concepts",q:"Which of the following BEST defines a TEST?",c:["A. A process of making judgments about the quality of a student's performance","B. An instrument designed to measure any characteristic, quality, ability, knowledge or skill","C. The collection and interpretation of qualitative and quantitative information","D. A process of quantifying the degree to which someone possesses a given trait"],a:"B",e:"A TEST is an instrument designed to measure any characteristic, quality, ability, knowledge, or skill. It is comprised of items (questions and tasks) in the area it is designed to measure."},
  {id:"aol-002",d:"easy",t:"TMAE Concepts",q:"MEASUREMENT is best defined as:",c:["A. A process of making judgments about student performance","B. An instrument used to assess quality and ability","C. A process of quantifying the degree to which someone possesses a given trait, quality, or characteristic","D. The collection of information to assist teachers in decision-making"],a:"C",e:"Measurement is a process of QUANTIFYING the degree to which someone/something possesses a given trait, quality, characteristics, or feature — assigning numbers to results."},
  {id:"aol-003",d:"easy",t:"TMAE Concepts",q:"The word ASSESSMENT comes from the Latin word 'assidere' which means:",c:["A. To judge","B. To measure","C. To sit beside","D. To evaluate"],a:"C",e:"Assessment is derived from the Latin 'assidere' which means 'to sit beside.' Assessment can be defined both as a product and as a process."},
  {id:"aol-004",d:"easy",t:"TMAE Concepts",q:"EVALUATION involves:",c:["A. Assigning numbers to the results of a test","B. Collecting qualitative and quantitative information","C. Making judgments about the quality of a performance, product, skill, or behavior of a student","D. Measuring the degree to which someone possesses a given trait"],a:"C",e:"Evaluation involves making JUDGMENTS about the quality of a performance, product, skill, or behavior of a student. It includes using some basis to judge worth or value."},
  {id:"aol-005",d:"easy",t:"TMAE Concepts",q:"Assessment is a pre-requisite to evaluation because it:",c:["A. Is more important than evaluation in the teaching-learning process","B. Provides the information which enables evaluation to take place","C. Involves making judgments about student performance","D. Is the same as measurement in educational settings"],a:"B",e:"Assessment provides the information which enables evaluation to take place. Hence, assessment is a pre-requisite to evaluation."},
  {id:"aol-006",d:"easy",t:"Purposes of Assessment",q:"Assessment FOR Learning includes which THREE types of assessment?",c:["A. Formative, Summative, and Authentic","B. Placement, Diagnostic, and Formative","C. Summative, Portfolio, and Rubric-based","D. Diagnostic, Summative, and Self-assessment"],a:"B",e:"Assessment FOR Learning includes THREE types: (1) Placement Assessment, (2) Diagnostic Assessment, and (3) Formative Assessment — all done BEFORE and DURING instruction."},
  {id:"aol-007",d:"easy",t:"Purposes of Assessment",q:"Assessment OF Learning is done:",c:["A. Before instruction to determine student readiness","B. During instruction to provide ongoing feedback","C. After instruction to evaluate learning at the end of a period","D. As students self-assess their own learning progress"],a:"C",e:"Assessment OF Learning (also called Summative Assessment) is done AFTER instruction — used to evaluate student learning at the end of a defined instructional period."},
  {id:"aol-008",d:"easy",t:"Purposes of Assessment",q:"Assessment AS Learning is associated with:",c:["A. Placement to determine the needs of learners","B. Summative evaluation done after instruction","C. Self-assessment and metacognition — students learning through the act of assessment itself","D. Diagnostic testing to find recurring difficulties"],a:"C",e:"Assessment AS Learning is associated with self-assessment — as students assess their own work, the assessment itself is already a form of learning. Students set targets and actively monitor their own learning."},
  {id:"aol-009",d:"easy",t:"Placement Assessment",q:"Placement Assessment is done BEFORE instruction. Its primary purpose is to:",c:["A. Determine whether learning has taken place at the end of the course","B. Diagnose recurring difficulties that don't respond to first-aid treatment","C. Assess the needs of learners to have basis in planning a relevant instruction","D. Provide students with feedback to improve their own learning"],a:"C",e:"Placement Assessment is done prior to or before instruction. Its purpose is to assess the NEEDS of the learners to have basis in planning a relevant instruction, and to place students in specific learning groups."},
  {id:"aol-010",d:"easy",t:"Diagnostic Assessment",q:"Which of the following is the PRIMARY purpose of Diagnostic Assessment?",c:["A. To evaluate student learning at the end of a defined instructional period","B. To determine what students already know and don't know to guide instruction","C. To provide grades as basis for decision-making by parents and stakeholders","D. To certify whether students have achieved curriculum outcomes"],a:"B",e:"Diagnostic Assessment is done BEFORE instruction and is used to diagnose what students already know and don't know yet in order to guide instruction. It also identifies recurring or persistent difficulties."},
  {id:"aol-011",d:"easy",t:"Formative Assessment",q:"Formative Assessment is done DURING instruction. Its main purpose is to:",c:["A. Assign final grades at the end of the school year","B. Place students into appropriate learning groups","C. Ensure that learning takes place by providing ongoing feedback to improve teaching and learning","D. Evaluate student learning at the end of a defined instructional period"],a:"C",e:"Formative Assessment is done DURING instruction. It is meant to ENSURE that learning takes place, provides the teacher with information on how well learning objectives are being met, and gives ongoing feedback."},
  {id:"aol-012",d:"easy",t:"Summative Assessment",q:"Summative Assessment is MOST used for:",c:["A. Diagnosing students' prior knowledge before teaching","B. Providing formative feedback during instruction","C. Placing students in specific learning groups","D. Evaluating student learning at the end of an instructional period; results are bases for grades"],a:"D",e:"Summative Assessment (Assessment OF Learning) is done AFTER instruction. Results are the BASES FOR GRADES which are communicated to students, parents, and stakeholders for decision-making."},
  {id:"aol-013",d:"easy",t:"Modes of Assessment",q:"Traditional Assessment includes the use of:",c:["A. Portfolio assessment and reflection journals","B. Performance tasks and authentic demonstrations","C. Paper-and-pencil tests","D. Real-life tasks requiring higher-order thinking"],a:"C",e:"Traditional Assessment (also called Decontextualized Assessment) includes the use of PAPER-AND-PENCIL TESTS — it focuses on declarative and/or procedural knowledge in artificial situations detached from the real world."},
  {id:"aol-014",d:"easy",t:"Modes of Assessment",q:"Authentic Assessment is also known as:",c:["A. Traditional Assessment","B. Decontextualized Assessment","C. Paper-and-Pencil Assessment","D. Performance or Alternative/Non-traditional Assessment"],a:"D",e:"Authentic Assessment is also known as PERFORMANCE or ALTERNATIVE/NON-TRADITIONAL assessment. It requires real-life tasks and requires students to utilize higher-order thinking skills (HOTS)."},
  {id:"aol-015",d:"easy",t:"Modes of Assessment",q:"Authentic Assessment is 'authentic' because:",c:["A. It is based solely on paper-and-pencil test results","B. It focuses on declarative knowledge detached from the real world","C. Students' knowledge and skill are assessed in a context that approximates the real world","D. It assigns numbers to student performance using standardized tests"],a:"C",e:"Authentic Assessment is AUTHENTIC because students' knowledge and skill are assessed in a context that approximates the real world or real life as closely as possible — it requires REAL-LIFE tasks."},
  {id:"aol-016",d:"easy",t:"Portfolio Assessment",q:"The word PORTFOLIO comes from the Latin 'portare' (carry) and 'foglio' (sheet of paper). A portfolio is:",c:["A. A standardized paper-and-pencil test","B. A systematic, organized, and purposeful collection of student's work","C. A single comprehensive test administered at the end of the year","D. A teacher's record of student grades throughout the school year"],a:"B",e:"A portfolio is a systematic, organized, and PURPOSEFUL collection of student's work that demonstrates the student's progress, skills, and accomplishments."},
  {id:"aol-017",d:"easy",t:"Portfolio Assessment",q:"Which of the following is NOT among the required contents of a portfolio?",c:["A. Student participation in selecting contents","B. Criteria for selection","C. Teacher's personal diary about the student","D. Evidence of self-reflection"],a:"C",e:"The portfolio collection must include: (1) Student participation in selecting contents, (2) Criteria for selection, (3) Criteria for judging merit, and (4) Evidence of self-reflection. A teacher's personal diary is NOT part of it."},
  {id:"aol-018",d:"easy",t:"Portfolio Types",q:"The DISPLAY, SHOWCASE, or BEST WORK PORTFOLIO presents:",c:["A. What a student has learned based on intended learning outcomes","B. Evidence of student change and growth over an extended time frame","C. The most outstanding work — the best efforts, best product, or best performance","D. A diagnosis of student learning challenges and difficulties"],a:"C",e:"The Display, Showcase, or Best Work Portfolio presents the MOST OUTSTANDING WORK of the student — their best efforts, best product, or the best performance. Useful for parent-teacher conferences and college admissions."},
  {id:"aol-019",d:"easy",t:"Scoring Rubric",q:"A Scoring Rubric is best described as:",c:["A. A standardized paper-and-pencil test for measuring academic performance","B. A scoring guide used to assess performance (process or product) against a set of criteria with descriptions of performance levels","C. A single number assigned to represent a student's overall performance","D. A portfolio collection of the student's best work"],a:"B",e:"A Scoring Rubric is a scoring GUIDE used to assess performance (process or product) against a set of criteria that includes descriptions of levels of performance quality on the criteria."},
  {id:"aol-020",d:"easy",t:"Scoring Rubric",q:"The TWO PARTS of a Scoring Rubric are:",c:["A. Difficulty Index and Discrimination Index","B. Coherent sets of criteria and Descriptions of levels of performance for those criteria","C. True-False items and Multiple Choice items","D. Summative score and Formative score"],a:"B",e:"The two parts of a Scoring Rubric are: (1) Coherent sets of CRITERIA, and (2) Descriptions of the LEVELS OF PERFORMANCE for these criteria (with weight and descriptor)."},
  {id:"aol-021",d:"easy",t:"Types of Rubrics",q:"A HOLISTIC RUBRIC describes:",c:["A. The quality of each individual dimension of performance independently","B. The overall quality of a performance or product with only ONE rating for the entire work","C. The degree to which the criterion satisfied or not by the performance","D. A detailed description of strengths and weaknesses in each criterion"],a:"B",e:"A Holistic Rubric describes the OVERALL QUALITY of a performance or product — there is only ONE rating given to the entire work or performance. It allows fast assessment."},
  {id:"aol-022",d:"easy",t:"Types of Rubrics",q:"An ANALYTIC RUBRIC:",c:["A. Gives one single overall score for the entire performance","B. Does not permit differential weighting of qualities","C. Describes the quality of a performance in terms of identified dimensions rated independently to give a better picture","D. Is faster to use than a holistic rubric"],a:"C",e:"An Analytic Rubric describes the quality of a performance in terms of identified dimensions, each rated independently. It permits differential weighting of qualities and helps pinpoint specific strengths and weaknesses."},
  {id:"aol-023",d:"easy",t:"Principles of Assessment",q:"PRINCIPLE 1 of High-Quality Classroom Assessment states that learning targets should be:",c:["A. Extremely broad to cover all possible student abilities","B. Clearly stated, specific, and centered on what is truly important (SMART)","C. Focused only on summative outcomes at the end of the year","D. Based solely on standardized national examination content"],a:"B",e:"Principle 1 (Clear and Appropriate Learning Targets) — learning targets should be clearly stated, SPECIFIC, and centered on what is truly important. Learning targets should be SMART: Specific, Measurable, Attainable, Result-oriented, Time-bound."},
  {id:"aol-024",d:"easy",t:"Types of Tests",q:"SELECTED-RESPONSE TYPE tests include:",c:["A. Short answer, essay, and problem-solving items","B. Completion type and essay items","C. True-False, Multiple Choice, and Matching Type tests","D. Portfolio and performance task assessments"],a:"C",e:"Selected-Response Type (paper-and-pencil tests where students choose from given options) includes: Alternate Response (True-False), Multiple Choice, and Matching Type tests."},
  {id:"aol-025",d:"easy",t:"Types of Tests",q:"CONSTRUCTED-RESPONSE TYPE (Supply Type) tests require students to:",c:["A. Choose from given answer options","B. Mark True or False for declarative statements","C. Supply or construct their own answers without choices","D. Match items in two columns"],a:"C",e:"Constructed-Response Type (Supply Type) includes tests where students SUPPLY their own answers WITHOUT CHOICES — examples include completion type (fill-in-the-blank) and essay tests."},
  {id:"aol-026",d:"easy",t:"True-False Tests",q:"The True-False test is also called the:",c:["A. Multiple Choice Test","B. Completion Type Test","C. Alternate Response or Selected-Response Test","D. Essay Test"],a:"C",e:"The True-False test is called the Alternate Response test — it consists of declarative statements that students must mark true or false, right or wrong, correct or incorrect, yes or no, fact or opinion."},
  {id:"aol-027",d:"easy",t:"True-False Tests",q:"Which of the THREE FORMS of True-False tests requires a conditional completion response and is also called the 'Modified True or False'?",c:["A. Simple — only two choices","B. Complex — more than two choices","C. Compound — two choices plus a conditional completion response","D. Paired — pairs of true-false statements"],a:"C",e:"COMPOUND (Modified True or False) — consists of two choices (True/False) PLUS a conditional completion response (explain why). If false, what makes it false? Also called Modified True or False."},
  {id:"aol-028",d:"easy",t:"Multiple Choice Tests",q:"In a Multiple Choice item, the STEM is:",c:["A. The incorrect answer options (distractors)","B. The question or problem part of the item","C. The correct answer among the alternatives","D. The set of all choices provided to the student"],a:"B",e:"In a Multiple Choice item, the STEM is the question or problem part (the first part). The alternatives/options include a 'correct' or 'best' option while all others are considered 'distractors.'"},
  {id:"aol-029",d:"easy",t:"Multiple Choice Tests",q:"The DISTRACTORS in a Multiple Choice test are:",c:["A. The correct answer among the alternatives","B. The stem or question part of the item","C. All the incorrect alternatives that distract students who don't know the answer","D. The instructions given at the beginning of the test"],a:"C",e:"Distractors are the INCORRECT options/alternatives in a multiple choice item — they are also called 'foils,' 'decoys,' or 'distractors.' All choices other than the correct answer are distractors."},
  {id:"aol-030",d:"easy",t:"Matching Type Tests",q:"In a Matching Type test, COLUMN A contains the:",c:["A. Responses from which a match is selected","B. Premises from which a match is sought","C. Answer key and correct responses","D. Distractors added to confuse students"],a:"B",e:"Column A contains the PREMISES from which a match is sought. Column B contains the RESPONSES from which the selection is made."},
  {id:"aol-031",d:"easy",t:"Essay Tests",q:"A RESTRICTED ESSAY has:",c:["A. No definite answer and is completely open-ended","B. A definite answer — it is a limited essay with a specific correct response","C. More than two possible correct answers","D. No guidelines given to students for responding"],a:"B",e:"A RESTRICTED ESSAY (Limited Essay) has a DEFINITE ANSWER — it is a limited essay with a specific expected response. Contrasted with Extended Essay which is open-ended with no single specific answer."},
  {id:"aol-032",d:"easy",t:"Validity",q:"VALIDITY is best defined as:",c:["A. The consistency of scores obtained by the same person when retested","B. The degree to which the assessment instrument measures what it intends to measure","C. The ease with which the test can be administered and scored","D. The ability of a test to discriminate between high and low performers"],a:"B",e:"Validity is the degree to which the assessment instrument MEASURES WHAT IT INTENDS TO MEASURE. It also refers to the usefulness of the instrument for a given purpose. It is the MOST IMPORTANT criterion of a good assessment instrument."},
  {id:"aol-033",d:"easy",t:"Validity",q:"CONTENT VALIDITY is established by:",c:["A. Examining the physical appearance of the instrument","B. Correlating test scores with scores obtained in another external predictor","C. A careful and critical examination of the objectives of assessment so that it reflects the curricular objectives","D. Comparing scores from two parallel forms of the test administered simultaneously"],a:"C",e:"Content Validity (also called the Table of Specifications/TOS) is done through a careful and critical examination of the OBJECTIVES of assessment so that it reflects the curricular objectives."},
  {id:"aol-034",d:"easy",t:"Validity",q:"FACE VALIDITY is established by:",c:["A. Examining the objectives of assessment to ensure curricular alignment","B. Correlating test scores with external predictors","C. Examining the physical appearance of the instrument (e.g., colors, layout)","D. Administering two parallel forms of the test simultaneously"],a:"C",e:"Face Validity is established by examining the PHYSICAL APPEARANCE of the instrument — it is based on the look or physical characteristics of the assessment tool."},
  {id:"aol-035",d:"easy",t:"Reliability",q:"RELIABILITY refers to the:",c:["A. Degree to which the instrument measures what it intends to measure","B. Ability of the test to discriminate between high and low performers","C. Consistency of scores obtained by the same person when retested using the same instrument","D. Balance between cognitive, affective, and psychomotor domains in assessment"],a:"C",e:"Reliability refers to the CONSISTENCY OF SCORES obtained by the same person when retested using the same instrument/its parallel or when compared with other students who took the same test. Also called stability."},
  {id:"aol-036",d:"easy",t:"Reliability Methods",q:"The TEST-RETEST METHOD measures which type of reliability?",c:["A. Internal consistency","B. Equivalence","C. Stability","D. Stability and equivalence combined"],a:"C",e:"Test-Retest is a measure of STABILITY — the same test is given twice to the same group with a time interval between tests (from several minutes to several years)."},
  {id:"aol-037",d:"easy",t:"Reliability Methods",q:"The SPLIT-HALF METHOD measures which type of reliability?",c:["A. Stability","B. Equivalence","C. Stability and equivalence","D. Internal consistency"],a:"D",e:"The Split-Half Method measures INTERNAL CONSISTENCY — a test is given once and split into equivalent halves (e.g., odd and even numbered items) and the scores of the two halves are correlated."},
  {id:"aol-038",d:"easy",t:"Item Analysis",q:"Item Analysis refers to:",c:["A. The process of creating test items using a Table of Specifications","B. The process of examining the student's response to each item in the test","C. The use of rubrics to score essay and performance tasks","D. The statistical process of computing the mean and standard deviation of test scores"],a:"B",e:"Item Analysis refers to the process of EXAMINING THE STUDENT'S RESPONSE to each item in the test. Items have two characteristics: desirable (retain) and undesirable (revise or reject)."},
  {id:"aol-039",d:"easy",t:"Item Difficulty",q:"Item Difficulty (Difficulty Index) is computed as:",c:["A. The number of students who FAILED to answer the item correctly divided by the total","B. The number of students who answered the item CORRECTLY divided by the total number of students","C. The difference between the upper group and lower group difficulty indices","D. The sum of all correct responses divided by the number of items"],a:"B",e:"Item Difficulty = Number of students with CORRECT ANSWER ÷ Total number of students. It tells us the proportion of students who got the item right."},
  {id:"aol-040",d:"easy",t:"Item Difficulty",q:"A Difficulty Index of 0.76 and above indicates the item is:",c:["A. Difficult — Revise or Discard","B. Right Difficulty — Retain","C. Easy — Revise or Discard","D. Non-discriminating — Revise"],a:"C",e:"Difficulty Index 0.76 and above = EASY item = Revise or Discard. Range 0.26-0.75 = Right Difficulty = Retain. Range 0-0.25 = Difficult = Revise or Discard."},
  {id:"aol-041",d:"easy",t:"Item Discrimination",q:"The Discrimination Index (D) is computed as:",c:["A. Number of correct answers divided by total students","B. Upper 27% difficulty index minus Lower 27% difficulty index (DU - DL)","C. Total score of upper group minus total score of lower group","D. Number of students who passed divided by number who failed"],a:"B",e:"Discrimination Index = DU - DL, where DU = difficulty index of upper group and DL = difficulty index of lower group (upper and lower 27%)."},
  {id:"aol-042",d:"easy",t:"Item Discrimination",q:"A Discrimination Index of 0.46 to 1.0 indicates the item is:",c:["A. Should be discarded — discriminates questionably","B. Non-discriminating — should be revised","C. Discriminating — should be included","D. Perfectly discriminating — should be used without modification"],a:"C",e:"Discrimination Index 0.46 to 1.0 = DISCRIMINATING ITEM = Include. Range -0.55 to 0.45 = Non-discriminating = Revise. Range -1.0 to -0.56 = Can discriminate but item is questionable = Discard."},
  {id:"aol-043",d:"easy",t:"Measures of Central Tendency",q:"The MEAN is also referred to as the:",c:["A. Centermost score in the distribution","B. Score that occurs most frequently","C. Average or arithmetic mean of a set of scores","D. Middle value when scores are arranged in order"],a:"C",e:"The MEAN is also referred to as the AVERAGE or arithmetic mean. It is the most commonly used measure of central tendency and is easily affected by extreme scores (outliers)."},
  {id:"aol-044",d:"easy",t:"Measures of Central Tendency",q:"The MEDIAN refers to:",c:["A. The score that occurs most frequently in the distribution","B. The arithmetic average of all scores","C. The centermost score when scores are arranged according to magnitude","D. The sum of all scores divided by the number of scores"],a:"C",e:"The MEDIAN refers to the CENTERMOST SCORES when scores in the distribution are arranged according to magnitude (highest to lowest or lowest to highest). It is NOT affected by extreme scores."},
  {id:"aol-045",d:"easy",t:"Measures of Central Tendency",q:"The MODE refers to:",c:["A. The arithmetic average of all scores","B. The middle score in an ordered distribution","C. The score or scores that occur most frequently in the distribution","D. The difference between the highest and lowest scores"],a:"C",e:"The MODE refers to the score or scores that OCCUR MOST FREQUENTLY in the score distribution. It can be used for quantitative and qualitative data. May not exist. Not affected by extreme values."},
  {id:"aol-046",d:"easy",t:"Measures of Central Tendency",q:"A score distribution with TWO MODES is called:",c:["A. Unimodal","B. Bimodal","C. Trimodal","D. Multimodal"],a:"B",e:"A BIMODAL distribution consists of TWO MODES — two scores that each occur most frequently. UNIMODAL = one mode. TRIMODAL = three modes. MULTIMODAL (Trimodal+) = more than two modes."},
  {id:"aol-047",d:"easy",t:"Measures of Variability",q:"Measures of Variability describe:",c:["A. The typical value in a set of scores","B. The shape of the frequency distribution","C. The spread of scores in a distribution — how far scores are above or below the measures of central tendency","D. The relationship between two sets of scores"],a:"C",e:"Measures of Variability are single values used to describe the SPREAD OF SCORES in a distribution — how far scores are above or below the measures of central tendency."},
  {id:"aol-048",d:"easy",t:"Measures of Variability",q:"The three measures of variability are:",c:["A. Mean, Median, and Mode","B. Range, Quartile Deviation, and Standard Deviation","C. Validity, Reliability, and Balance","D. Skewness, Kurtosis, and Normal Distribution"],a:"B",e:"The THREE MEASURES OF VARIABILITY are: (1) Range, (2) Quartile Deviation (QD), and (3) Standard Deviation (SD)."},
  {id:"aol-049",d:"easy",t:"Range",q:"The RANGE is computed as:",c:["A. The average of the highest and lowest scores","B. The sum of all scores minus the mean","C. The difference between the highest score and lowest score (HS - LS)","D. The middle 50% of scores in the distribution"],a:"C",e:"Range = Highest Score (HS) - Lowest Score (LS). It is the simplest but roughest measure of variability. Easily affected by extreme scores and very easy to compute."},
  {id:"aol-050",d:"easy",t:"Standard Deviation",q:"The STANDARD DEVIATION (SD) is described as:",c:["A. The difference between the highest and lowest scores","B. The average deviation of the third and first quartiles from the median","C. The most important measure and most commonly used measure of variability or dispersion","D. The middle 50% of scores that reduces the influence of extreme scores"],a:"C",e:"Standard Deviation (SD) shows the variation of individual scores about the MEAN. It is the MOST IMPORTANT and MOST COMMONLY USED measure of variation or dispersion, particularly in research."},
  {id:"aol-051",d:"easy",t:"Quartile Deviation",q:"The QUARTILE DEVIATION (QD):",c:["A. Is the most important measure of variability used in research","B. Is the difference between the highest and lowest scores","C. Considers only the middle 50% of scores and reduces the influence of extreme scores","D. Shows variation of individual scores about the mean"],a:"C",e:"Quartile Deviation (QD) refers to the average deviation of the 3rd quartile and the 1st quartile from the median. It considers ONLY THE MIDDLE 50% of scores and reduces the influence of extreme scores."},
  {id:"aol-052",d:"easy",t:"Skewness",q:"A POSITIVELY SKEWED distribution is skewed to the:",c:["A. Left — most scores are above the mean","B. Right — most scores are below the mean","C. Center — scores are normally distributed","D. Neither direction — it is symmetric"],a:"B",e:"POSITIVELY SKEWED = skewed to the RIGHT = thin end tail goes to the RIGHT. Most scores are BELOW the mean. Associated with poor performance; tells the test was DIFFICULT. (PRDL: Positive=Right=Difficult=Low)"},
  {id:"aol-053",d:"easy",t:"Skewness",q:"A NEGATIVELY SKEWED distribution is described as:",c:["A. A distribution where most scores are below the mean and the test was difficult","B. A distribution where most scores are ABOVE the mean — test was EASY","C. A symmetric distribution where mean = median = mode","D. A distribution where the tail extends equally in both directions"],a:"B",e:"NEGATIVELY SKEWED = skewed to the LEFT = thin end tail goes to the LEFT. Most scores are ABOVE the mean. Associated with good performance; tells the test was EASY. (NLEH: Negative=Left=Easy=High)"},
  {id:"aol-054",d:"easy",t:"Normal Distribution",q:"In a NORMAL DISTRIBUTION, the relationship between mean, median, and mode is:",c:["A. Mean > Median > Mode (Positively Skewed)","B. Mode > Median > Mean (Negatively Skewed)","C. Mode = Median = Mean","D. Mean = Mode but not Median"],a:"C",e:"In a NORMALLY DISTRIBUTED score, Mode = Median = Mean. The normal distribution is a special kind of symmetric distribution — bell-shaped and symmetrical to the mean."},
  {id:"aol-055",d:"easy",t:"Normal Distribution",q:"In the Normal Distribution, what percentage of scores falls within ±1 standard deviation of the mean?",c:["A. 34.13%","B. 68.26%","C. 95.44%","D. 99.72%"],a:"B",e:"Within ±1 SD: 68.26% (34.13% on each side). Within ±2 SD: 95.44%. Within ±3 SD: 99.72%."},
  {id:"aol-056",d:"easy",t:"Kurtosis",q:"MEASURES OF KURTOSIS tell us about:",c:["A. The degree of departure from symmetry in a distribution","B. The shape of a group of data — whether tall/narrow, flat/wide, or just normal","C. The spread of scores about the mean","D. The relationship between two variables"],a:"B",e:"Measures of Kurtosis tell us the SHAPE of a group of data. It shows if the data is: Tall and narrow (Leptokurtic), Flat and wide (Platykurtic), or Just normal (Mesokurtic)."},
  {id:"aol-057",d:"easy",t:"Kurtosis",q:"A LEPTOKURTIC curve is described as:",c:["A. A flat, wide curve with scores spread out — looks flat","B. A normal, bell-shaped curve — scores are just right","C. A very high, peaked, narrow curve — many scores very close together","D. A distribution skewed to the right"],a:"C",e:"LEPTOKURTIC = very HIGH PEAK, TALL and NARROW curve. Many scores are very close together and some are very far (very high or very low). Example: Easy quiz where most score 90-100 but a few score 50."},
  {id:"aol-058",d:"easy",t:"Kurtosis",q:"A PLATYKURTIC curve is characterized by:",c:["A. A tall, narrow, highly peaked curve","B. A normal, bell-shaped curve","C. A flat, wide curve with scores spread out and no big group in the middle","D. A distribution where most scores are above the mean"],a:"C",e:"PLATYKURTIC = FLAT and WIDE curve. Scores are SPREAD OUT, no big group in the middle. Looks flat. Example: Hard exam where scores range from 40 to 95 with different abilities spread throughout."},
  {id:"aol-059",d:"easy",t:"Measures of Relative Position",q:"PERCENTILE RANK indicates:",c:["A. The number of standard deviations a score is from the mean","B. The percentage of examinees in the norm group who scored BELOW the score of interest","C. The location of a score in a normal distribution with mean 50 and SD 10","D. The raw score expressed in units of standard deviation"],a:"B",e:"Percentile Rank = the percentage of examinees in the norm group who scored BELOW the score of interest. Example: Maria's score of 82 = 90th percentile means 90% of classmates scored lower than 82."},
  {id:"aol-060",d:"easy",t:"Measures of Relative Position",q:"STANINES are single-digit scores ranging from:",c:["A. 0 to 10","B. 1 to 9","C. 1 to 100","D. -3 to +3"],a:"B",e:"STANINES (Standard Nines) are single-digit scores ranging from 1 to 9. The distribution of raw scores is divided into NINE parts. Stanine 5 = Average, Stanines 7-9 = Above Average to Very High, Stanines 1-3 = Very Low to Below Average."},

  // ==================== MODERATE (100) ====================
  {id:"aol-061",d:"moderate",t:"TMAE Concepts",q:"A teacher gives 10 Grade 7 students a quiz on fractions. She assigns each student a score from 0-30. This process of assigning numbers to student performance is BEST described as:",c:["A. Evaluation — making judgments about performance","B. Measurement — quantifying the degree to which students possess the skill","C. Authentic Assessment — approximating real-world performance","D. Formative Assessment — monitoring progress during instruction"],a:"B",e:"MEASUREMENT is the process of assigning numbers to results — quantifying the degree to which students possess a given skill. Giving scores (0-30) to a quiz is the act of measurement."},
  {id:"aol-062",d:"moderate",t:"TMAE Concepts",q:"A teacher reviews quiz scores (measurement) and then says 'The class performed poorly and needs remediation.' This conclusion represents:",c:["A. Assessment — collecting information","B. Testing — using an instrument to measure","C. Evaluation — making a judgment about the quality of performance based on the data","D. Placement — assigning students to appropriate groups"],a:"C",e:"EVALUATION involves making JUDGMENTS about performance quality. The teacher has used the data (measurement) to make a judgment (poor performance → needs remediation) = Evaluation."},
  {id:"aol-063",d:"moderate",t:"Purposes of Assessment",q:"A teacher gives a pretest before starting a new unit on photosynthesis to find out what students already know. This is an example of:",c:["A. Summative Assessment — to grade students at the end of the unit","B. Formative Assessment — to provide feedback during instruction","C. Diagnostic Assessment — to find out what students already know before instruction begins","D. Self-assessment — to encourage metacognitive awareness"],a:"C",e:"DIAGNOSTIC Assessment is done BEFORE instruction to determine what students already know and don't know yet in order to guide instruction. A pretest before a new unit is classic Diagnostic Assessment."},
  {id:"aol-064",d:"moderate",t:"Purposes of Assessment",q:"A teacher administers exit tickets at the end of each class to check if students understood the lesson and provides immediate feedback the next day. This BEST describes:",c:["A. Placement Assessment","B. Diagnostic Assessment","C. Summative Assessment","D. Formative Assessment"],a:"D",e:"FORMATIVE Assessment is done DURING instruction, provides the teacher with information on how well learning objectives are being met, and gives ON-GOING FEEDBACK. Exit tickets with immediate feedback = classic Formative Assessment."},
  {id:"aol-065",d:"moderate",t:"Purposes of Assessment",q:"A student reviews her portfolio, reflects on her growth, and sets new learning targets for the semester. This BEST exemplifies:",c:["A. Assessment OF Learning — summative and grade-based","B. Assessment FOR Learning — placement and diagnostic","C. Assessment AS Learning — self-assessment, metacognition, and self-directed learning","D. Formative Assessment — teacher-directed feedback during instruction"],a:"C",e:"Assessment AS Learning — students SET THEIR TARGETS, ACTIVELY MONITOR, and EVALUATE their own learning. Students become self-directed and independent learners. The portfolio reflection is a classic AS Learning tool."},
  {id:"aol-066",d:"moderate",t:"Portfolio Assessment",q:"A teacher creates a portfolio where students collect their best works from throughout the school year to present at parent-teacher conferences and for college applications. This is BEST described as a:",c:["A. Assessment or Evaluation Portfolio — documents learning based on intended outcomes","B. Working, Growth, or Development Portfolio — shows change over time","C. Display, Showcase, or Best Work Portfolio — presents most outstanding work","D. Diagnostic Portfolio — identifies learning difficulties and misconceptions"],a:"C",e:"DISPLAY/SHOWCASE/BEST WORK PORTFOLIO — presents the most outstanding work. Useful for parent-teacher conferences, college admissions, and future job applications. Leads students to celebrate learning."},
  {id:"aol-067",d:"moderate",t:"Portfolio Assessment",q:"A Kindergarten teacher collects samples of students' name-writing from the beginning, middle, and end of the school year. This BEST represents:",c:["A. Display Portfolio — showcasing the best work","B. Assessment Portfolio — documenting learning based on intended learning outcomes","C. Working, Growth, or Development Portfolio — reveals student progress and change over time","D. Diagnostic Portfolio — finding recurring learning difficulties"],a:"C",e:"WORKING/GROWTH/DEVELOPMENT PORTFOLIO — consists of student work over an extended time frame to reveal student's progress in meeting learning targets and provide evidence of how much a student has changed or developed over time."},
  {id:"aol-068",d:"moderate",t:"Portfolio Types",q:"Which type of portfolio is MOST useful for a teacher who wants to document what a student has learned based on the intended learning outcomes and objectives?",c:["A. Display Portfolio — for showcasing outstanding work","B. Working Portfolio — for tracking progress over time","C. Assessment or Evaluation Portfolio — for documenting learning based on intended learning outcomes","D. Best Work Portfolio — for college and job applications"],a:"C",e:"ASSESSMENT or EVALUATION PORTFOLIO — intended to document what a student has learned based on the INTENDED LEARNING OUTCOMES, objectives, and competencies. Meant to diagnose student learning."},
  {id:"aol-069",d:"moderate",t:"Classes of Portfolio Evidence",q:"Teacher's evaluative notes about a student's oral defense of a research paper would be classified as which type of portfolio evidence?",c:["A. Artifacts — documents produced inside the classroom","B. Reproductions — documentations of work outside the classroom","C. Attestations — teacher or other responsible persons' documentations to attest progress","D. Productions — documents that the student prepares for themselves"],a:"C",e:"ATTESTATIONS — the teacher or other responsible persons' documentations to attest to the student's progress. Teacher's evaluative notes about oral defense = attestation."},
  {id:"aol-070",d:"moderate",t:"Classes of Portfolio Evidence",q:"A student's capstone project and a description of an interview with the Education Committee Chairman are stored in their portfolio. These are examples of:",c:["A. Artifacts — products from academic classroom work","B. Reproductions — documentations of student work OUTSIDE the classroom","C. Attestations — teacher's notes about the student's progress","D. Productions — goal statements prepared by the student"],a:"B",e:"REPRODUCTIONS — documentations of a student's work OUTSIDE the classroom. Special projects like capstone and descriptions of interviews outside school are classic reproductions."},
  {id:"aol-071",d:"moderate",t:"Scoring Rubric",q:"A teacher scores a student's oral presentation using a checklist of criteria, each scored independently (voice, content, organization, delivery). This BEST describes:",c:["A. Holistic Rubric — one overall rating for the entire performance","B. Analytic Rubric — each identified dimension rated independently","C. Alternate Response Scoring — marking True or False","D. Completion Type Scoring — filling in blanks"],a:"B",e:"ANALYTIC RUBRIC — describes the quality of a performance in terms of identified dimensions, each rated INDEPENDENTLY to give a better picture. Helps raters pinpoint specific areas of strength and weakness."},
  {id:"aol-072",d:"moderate",t:"Scoring Rubric",q:"A teacher needs to quickly score 50 students' recitations with a single overall rating. Which type of rubric would be MOST EFFICIENT for this purpose?",c:["A. Analytic Rubric — provides detailed dimension-by-dimension feedback","B. Portfolio Assessment — systematic collection of student work","C. Holistic Rubric — one rating for the overall performance; allows fast assessment","D. Content Validity check — examining objectives against curricular goals"],a:"C",e:"HOLISTIC RUBRIC provides ONE SCORE to describe the OVERALL performance — allows FAST ASSESSMENT. Best when quick scoring of the whole performance is needed rather than detailed dimensional feedback."},
  {id:"aol-073",d:"moderate",t:"Principles of Assessment",q:"A teacher's test includes items measuring only cognitive knowledge (facts) while the curriculum requires cognitive, affective, and psychomotor learning. Which Principle of High-Quality Assessment is VIOLATED?",c:["A. Principle 1 — Clear and Appropriate Learning Targets","B. Principle 2 — Appropriate Assessment Methods","C. Principle 3 — BALANCED — assessing all domains of learning","D. Principle 4 — Validity"],a:"C",e:"PRINCIPLE 3: BALANCED — a balanced assessment sets target in ALL domains of learning (cognitive, affective, psychomotor) and makes use of both traditional and alternative assessment. Only testing cognitive = violating Balance."},
  {id:"aol-074",d:"moderate",t:"Principles of Assessment",q:"A test covers only 3 of the 10 learning objectives taught over a semester, ignoring 7 others. Which Principle of Assessment is MOST DIRECTLY violated?",c:["A. Principle 3 — Balance","B. Principle 4 — Validity (specifically Content Validity)","C. Principle 5 — Reliability","D. Minor Principle of Administrability"],a:"B",e:"PRINCIPLE 4: VALIDITY — specifically CONTENT VALIDITY. A test must reflect the curricular objectives. If 7 out of 10 objectives are not covered, the test does not measure what it intends to measure → Content Validity is violated."},
  {id:"aol-075",d:"moderate",t:"True-False Tests",q:"A True-False item states: 'The Philippines ALWAYS celebrates Independence Day on June 12.' The use of the word 'ALWAYS' violates which rule for constructing Alternate-Response tests?",c:["A. Rule #1 — Do not give hints in the body of the question","B. Rule #2 — Avoid sweeping terms like 'always,' 'never,' 'often' that tend to be always true or always false","C. Rule #3 — Avoid long sentences that tend to be true","D. Rule #7 — Avoid double negatives"],a:"B",e:"RULE #2 — Avoid using sweeping terms ('always,' 'never,' 'often,' 'much,' 'many') that tend to be either always true or always false. These are qualifying terms that tip students off."},
  {id:"aol-076",d:"moderate",t:"True-False Tests",q:"A teacher writes a True-False item that is 5 lines long and contains multiple clauses. This violates which rule?",c:["A. Rule #2 — Avoid sweeping terms","B. Rule #4 — Avoid trick statements","C. Rule #3 — Avoid long sentences as they tend to be 'true'","D. Rule #6 — Avoid disproportionate numbers of true or false statements"],a:"C",e:"RULE #3 — Avoid long sentences as they tend to be 'true.' Keep sentences SHORT. Long sentences allow students to guess correctly (true) even without knowing the content."},
  {id:"aol-077",d:"moderate",t:"Multiple Choice Tests",q:"A Multiple Choice stem reads: 'As compared to autos of the 1960s, autos in the 1980s ___.' The options are: A. Traveling slower, B. Bigger interiors, C. to use less fuel, D. contain more safety measure. Which rule is VIOLATED?",c:["A. Rule #1 — Do not use unfamiliar words","B. Rule #4 — Distractors should be equally plausible","C. Rule #5 — All choices should be grammatically consistent with the stem","D. Rule #3 — Avoid complex or awkward word arrangements"],a:"C",e:"RULE #5 — All choices should be GRAMMATICALLY CONSISTENT with the stem. Options A and B are gerunds (traveling, bigger) but don't complete the sentence properly. Options C and D use infinitives. Grammar inconsistency gives clues."},
  {id:"aol-078",d:"moderate",t:"Multiple Choice Tests",q:"A teacher writes a Multiple Choice item where two options are near-synonyms: A. Honesty, B. Frankness, C. Openness, D. Secrecy. This violates:",c:["A. Rule #1 — Avoid unfamiliar words","B. Rule #4 — Distractors should be equally plausible","C. Rule #7 — Avoid alternatives synonymous with others or those that include or overlap others","D. Rule #8 — Use 'None of the above' sparingly"],a:"C",e:"RULE #7 — Avoid alternatives that are SYNONYMOUS with others or those that include or overlap others. Honesty, Frankness, and Openness are near-synonyms — students who know one is wrong know the others are too."},
  {id:"aol-079",d:"moderate",t:"Matching Type Tests",q:"A Matching Type test has 10 PREMISES in Column A and 10 RESPONSES in Column B with no extras. This violates which guideline?",c:["A. Rule #1 — Match homogeneous items","B. Rule #2 — Stem must be in first column, options in second","C. Rule #3 — Options must be MORE in number than stems — add two distractors","D. Rule #4 — Arrange options alphabetically"],a:"C",e:"RULE #3 — The options must be MORE IN NUMBER than the stems — add two or more distractors. Equal numbers allow students to guess the last answer by elimination."},
  {id:"aol-080",d:"moderate",t:"Essay Tests",q:"A teacher asks: 'If Rizal were alive today, what comments would he give on present Philippine politics?' This is an example of an:",c:["A. Restricted Essay — has a definite expected answer","B. Completion Type item — fill-in-the-blank","C. Extended Essay — open-ended, no single specific answer","D. True-False item — requires a true or false response"],a:"C",e:"EXTENDED ESSAY — open-ended, no single specific answer (non-limited essay). The hypothetical question about Rizal's contemporary views has no single correct answer — it requires open-ended response."},
  {id:"aol-081",d:"moderate",t:"Essay Tests",q:"Essay Rule #4 states: 'Evaluate answers to essay questions WITHOUT KNOWING THE IDENTITY OF THE WRITER.' The primary reason for this rule is to:",c:["A. Save time during grading","B. Avoid bias — teacher's prior impression of a student may affect the grade","C. Ensure grammatical consistency across all answers","D. Allow multiple teachers to share grading responsibilities"],a:"B",e:"RULE #4 — evaluate answers WITHOUT knowing the identity of the writer TO AVOID BIAS. A teacher's prior impression or preference for a student may unfairly influence grading (halo effect/leniency bias)."},
  {id:"aol-082",d:"moderate",t:"Validity",q:"CRITERION-RELATED VALIDITY is established by:",c:["A. Examining the physical appearance of the assessment instrument","B. Reviewing the objectives to ensure they reflect curricular goals","C. Statistically correlating scores from the assessment with scores from another external predictor or measure","D. Administering the same test twice and correlating the two sets of scores"],a:"C",e:"CRITERION-RELATED VALIDITY is established statistically — the measuring instrument is CORRELATED with scores obtained in another external predictor or measure. It has two types: Concurrent and Predictive."},
  {id:"aol-083",d:"moderate",t:"Validity",q:"A reading test score is compared with the average reading grades given by the teacher this semester. This BEST illustrates which type of validity?",c:["A. Face Validity — examining physical appearance","B. Content Validity — checking curricular alignment","C. Predictive Validity — predicting future performance","D. Concurrent Validity — correlating present scores with another present measure"],a:"D",e:"CONCURRENT VALIDITY — describes the present status of the individual by correlating the sets of scores obtained from two measures given CONCURRENTLY (same time period). Reading test scores vs. current teacher grades = Concurrent Validity."},
  {id:"aol-084",d:"moderate",t:"Validity",q:"Entrance examination scores of freshmen are correlated with their average grades at the END of the school year. This illustrates:",c:["A. Concurrent Validity — two measures given at the same time","B. Face Validity — checking physical appearance of the exam","C. Predictive Validity — correlating scores with a FUTURE performance measure","D. Content Validity — checking curricular objectives"],a:"C",e:"PREDICTIVE VALIDITY — describes the FUTURE PERFORMANCE of an individual by correlating the sets of scores obtained from two measures given at a LONGER TIME INTERVAL. Entrance exam scores vs. end-of-year grades = Predictive Validity."},
  {id:"aol-085",d:"moderate",t:"Reliability Methods",q:"A teacher administers two different but equivalent forms of the same test within a close time interval to measure EQUIVALENCE of the test. Which reliability method is being used?",c:["A. Test-Retest Method — same test, twice","B. Equivalent Forms Method — parallel forms, close time interval","C. Split-Half Method — one test, divided into halves","D. Kuder-Richardson Method — correlates proportion passing and failing"],a:"B",e:"EQUIVALENT FORMS METHOD — measures EQUIVALENCE. Gives PARALLEL FORMS of tests with CLOSE TIME INTERVAL between forms. Contrasted with Test-Retest (same test, longer interval) and Test-Retest with Equivalent Forms (measures both stability and equivalence)."},
  {id:"aol-086",d:"moderate",t:"Item Analysis",q:"A teacher analyzes her test and finds an item with Difficulty Index = 0.20 and Discrimination Index = 0.50. What should she do with this item?",c:["A. Retain — both indices are acceptable","B. Revise — the difficulty index is 0.20 (difficult) but discrimination is good; may improve the difficulty","C. Discard — both indices are unacceptable","D. Keep as-is — the discrimination index compensates for the difficulty"],a:"B",e:"DI = 0.20 (Difficult/below 0.26 = Revise or Discard) BUT Discrimination = 0.50 (Good, 0.46-1.0 = Include). In the Retain-Revise-Reject matrix: DI NOT within 0.26-0.75 AND Discrimination WITHIN 0.20+ → REVISE (not discard)."},
  {id:"aol-087",d:"moderate",t:"Item Analysis",q:"An item has Difficulty Index = 0.50 and Discrimination Index = 0.15. What action is recommended?",c:["A. Retain — good difficulty but check discrimination","B. Revise — difficulty is right but discrimination is too low (below 0.20/0.46)","C. Discard — both indices are unacceptable","D. Include — discrimination above 0.15 is acceptable"],a:"B",e:"DI = 0.50 (Right Difficulty, within 0.26-0.75 = GOOD) BUT Discrimination = 0.15 (below 0.20 = NOT acceptable, -0.55 to 0.45 = Non-discriminating = REVISE). In the matrix: DI good + Discrimination bad = REVISE."},
  {id:"aol-088",d:"moderate",t:"Item Difficulty Computation",q:"In a class of 40 students, 30 students answered an item correctly. What is the Difficulty Index?",c:["A. 0.25 — Difficult","B. 0.50 — Right Difficulty","C. 0.75 — Right Difficulty (borderline Easy)","D. 0.80 — Easy"],a:"C",e:"Difficulty Index = Correct ÷ Total = 30 ÷ 40 = 0.75. Range 0.26-0.75 = RIGHT DIFFICULTY = RETAIN. At exactly 0.75, the item is at the borderline of Right Difficulty and Easy — retain."},
  {id:"aol-089",d:"moderate",t:"Item Discrimination Computation",q:"30 students take a test. The upper 27% group has 8 students; 6 answered item 1 correctly. The lower 27% has 8 students; 2 answered item 1 correctly. What is the Discrimination Index?",c:["A. D = 0.20","B. D = 0.40","C. D = 0.50","D. D = 0.75"],a:"C",e:"DU = 6/8 = 0.75; DL = 2/8 = 0.25. D = DU - DL = 0.75 - 0.25 = 0.50. Range 0.46-1.0 = DISCRIMINATING ITEM = Include."},
  {id:"aol-090",d:"moderate",t:"Mean Computation",q:"The scores of 5 students are: 80, 85, 90, 95, and 100. What is the MEAN?",c:["A. 88","B. 90","C. 92","D. 95"],a:"B",e:"Mean = Sum of all scores ÷ Number of scores = (80+85+90+95+100) ÷ 5 = 450 ÷ 5 = 90."},
  {id:"aol-091",d:"moderate",t:"Median Computation",q:"Find the MEDIAN of the following scores: 14, 35, 45, 55, 55, 56, 65, 87, 89, 92.",c:["A. 55","B. 55.5","C. 56","D. 60.5"],a:"B",e:"10 scores arranged in order. n=10 (even), so median = average of 5th and 6th scores. 5th score = 55, 6th score = 56. Median = (55+56)/2 = 111/2 = 55.5."},
  {id:"aol-092",d:"moderate",t:"Mode",q:"What is the MODE of the following scores: 14, 35, 45, 55, 55, 56, 65, 87, 89, 92?",c:["A. 45","B. 55","C. 56","D. 65"],a:"B",e:"MODE = the score that occurs MOST FREQUENTLY. Score 55 appears TWICE while all others appear once. Mode = 55."},
  {id:"aol-093",d:"moderate",t:"Mean vs. Median",q:"A teacher is reporting the 'typical' test score of a class where one student scored 98 and all others scored between 60-70. Which measure of central tendency should she use to AVOID distortion by the extreme score?",c:["A. Mean — most commonly used and most reliable","B. Mode — most frequently occurring score","C. Median — not affected by extreme scores; best when there are outliers","D. Range — shows the spread between highest and lowest"],a:"C",e:"MEDIAN is NOT AFFECTED by extreme scores because it is a POSITIONAL measure. When there are extreme scores (outliers), the median gives a more accurate picture of the 'typical' score than the mean."},
  {id:"aol-094",d:"moderate",t:"Range",q:"A teacher notes that her class scores ranged from 45 to 95. What is the RANGE, and what does a large range indicate?",c:["A. Range = 140; large range = homogeneous group","B. Range = 50; large range = large variability, scores are dispersed and heterogeneous","C. Range = 50; large range = small variability, scores are clustered","D. Range = 70; scores are concentrated in the middle"],a:"B",e:"Range = HS - LS = 95 - 45 = 50. LARGE RANGE = LARGE VARIABILITY = scores are DISPERSED, SCATTERED, far from each other = HETEROGENEOUS (more varied) group."},
  {id:"aol-095",d:"moderate",t:"Positively Skewed Distribution",q:"A teacher administers a very difficult test and gets these results: Mean = 55, Median = 60, Mode = 65. What type of distribution is this, and what does it indicate?",c:["A. Normal Distribution — mean = median = mode","B. Negatively Skewed — Mode > Median > Mean; test was easy, most scores HIGH","C. Positively Skewed — Mean < Median < Mode; most scores LOW, test was DIFFICULT","D. Bimodal Distribution — two peaks in the score distribution"],a:"C",e:"POSITIVELY SKEWED = Mean < Median < Mode (right tail). Most scores are BELOW the mean. The test was DIFFICULT, indicating poor student performance. (PRDL: Positive=Right=Difficult=Low)"},
  {id:"aol-096",d:"moderate",t:"Negatively Skewed Distribution",q:"After an easy test, a teacher finds: Mean = 80, Median = 75, Mode = 70. What type of distribution is this?",c:["A. Normal Distribution","B. Positively Skewed — thin tail goes right, most scores low","C. Negatively Skewed — Mean > Median > Mode; most scores HIGH, test was EASY","D. Bimodal Distribution"],a:"C",e:"NEGATIVELY SKEWED = Mean > Median > Mode (left tail). Most scores are ABOVE the mean. Test was EASY, students performed WELL. (NLEH: Negative=Left=Easy=High)"},
  {id:"aol-097",d:"moderate",t:"Normal Distribution",q:"In a normally distributed set of scores with mean=75 and SD=10, approximately what percentage of students scored between 65 and 85?",c:["A. 34.13%","B. 47.72%","C. 68.26%","D. 95.44%"],a:"C",e:"65 to 85 = mean ±1 SD (75-10=65 to 75+10=85). In a normal distribution, ±1 SD = 68.26% of all scores. So approximately 68.26% of students scored between 65 and 85."},
  {id:"aol-098",d:"moderate",t:"Z-Score",q:"Maria's score is 90, the class mean is 80, and the standard deviation is 5. What is her Z-Score?",c:["A. Z = -2.0","B. Z = 0.0","C. Z = +1.0","D. Z = +2.0"],a:"D",e:"Z = (Score - Mean) ÷ SD = (90 - 80) ÷ 5 = 10 ÷ 5 = +2.0. A positive Z-score means the score is ABOVE the mean. Maria scored 2 standard deviations above the class mean."},
  {id:"aol-099",d:"moderate",t:"Z-Score",q:"A student has a Z-score of -1.5. This means the student's score is:",c:["A. 1.5 standard deviations ABOVE the mean","B. 1.5 standard deviations BELOW the mean","C. At exactly the mean (Z=0)","D. At the 84th percentile"],a:"B",e:"A NEGATIVE Z-score gives the number of standard deviations a score is BELOW the mean. Z = -1.5 means the score is 1.5 standard deviations below the mean."},
  {id:"aol-100",d:"moderate",t:"T-Score",q:"If a student's Z-score is +1.5, what is the corresponding T-score?",c:["A. T = 35","B. T = 50","C. T = 65","D. T = 75"],a:"C",e:"T = 10z + 50 = 10(1.5) + 50 = 15 + 50 = 65. T-score uses a mean of 50 and SD of 10 in a normal distribution. T=50 = mean, T=60 = 1 SD above mean, T=65 = 1.5 SD above mean."},
  {id:"aol-101",d:"moderate",t:"T-Score",q:"T-scores tell the location of a score in a normal distribution having a mean of ____ and a standard deviation of ____.",c:["A. Mean = 0, SD = 1","B. Mean = 50, SD = 10","C. Mean = 100, SD = 15","D. Mean = 500, SD = 100"],a:"B",e:"T-scores use a MEAN OF 50 and a STANDARD DEVIATION OF 10. Formula: T = 10z + 50. A T-score of 50 = exactly at the mean; T = 60 = 1 SD above mean."},
  {id:"aol-102",d:"moderate",t:"Stanines",q:"A student's stanine score is 7. This places the student in which performance category?",c:["A. Very Low","B. Average","C. Above Average","D. Very High"],a:"C",e:"STANINE 7 = ABOVE AVERAGE. Stanine categories: 1=Very Low, 2-3=Below Average, 4-6=Average, 7-8=Above Average, 9=Very High. Stanine 7 is clearly Above Average."},
  {id:"aol-103",d:"moderate",t:"Measures of Relationship",q:"As students' study time INCREASES, their test scores also INCREASE. This relationship is BEST described as:",c:["A. Negative Correlation — indirect/inverse relation","B. No Correlation — no relationship between the variables","C. Positive Correlation — direct relation; as one increases, the other also increases","D. Zero Correlation — both variables move in opposite directions"],a:"C",e:"POSITIVE CORRELATION (Direct Relation) — as one variable INCREASES, the other variable also INCREASES. Study time and test scores both moving up = Positive Correlation."},
  {id:"aol-104",d:"moderate",t:"Measures of Relationship",q:"As the number of absences INCREASES, a student's grades DECREASE. This illustrates:",c:["A. Positive Correlation — direct relation","B. No Correlation — no relationship","C. Negative Correlation — indirect/inverse relation; as one increases, the other decreases","D. Zero Correlation"],a:"C",e:"NEGATIVE CORRELATION (Indirect/Inverse Relation) — as one variable INCREASES, the other variable DECREASES. More absences → lower grades = negative/inverse relationship."},
  {id:"aol-105",d:"moderate",t:"K-12 Curriculum",q:"The K-12 Curriculum is also known as the:",c:["A. New Elementary School Curriculum (NESC)","B. Basic Education Curriculum (BEC)","C. Revised Basic Education Curriculum (RBEC)","D. Enhanced Basic Education Curriculum under Republic Act 10533"],a:"D",e:"K-12 Curriculum = ENHANCED BASIC EDUCATION CURRICULUM — implemented under RA 10533 (Enhanced Basic Education Act of 2013). Named K-12 because it has KINDERGARTEN plus 12 GRADE LEVELS."},
  {id:"aol-106",d:"moderate",t:"K-12 Curriculum",q:"The K-12 Curriculum differs from the 2002 BEC because it adds:",c:["A. 3 years of elementary education","B. 2 years of high school (Grade 11-12: Senior High School)","C. One year of preschool education","D. 4 additional years of college"],a:"B",e:"2002 BEC = 6 years elementary + 4 years HS = 10 years. K-12 = Mandatory Kindergarten + 6 years elementary + 4 years Junior HS (7-10) + 2 years Senior HS (11-12) = 13 years total including Kinder."},
  {id:"aol-107",d:"moderate",t:"Modes of Assessment",q:"A teacher asks students to perform a science experiment and write a lab report demonstrating their ability to apply scientific method. Authentic Assessment COMPLEMENTS Traditional Assessment. Which of the following BEST explains why both are needed?",c:["A. Traditional Assessment is outdated and should be replaced entirely","B. Authentic Assessment measures declarative knowledge more accurately than traditional tests","C. Traditional Assessment measures foundational knowledge efficiently; Authentic Assessment assesses application in real-world contexts — both together provide a balanced picture","D. Both types of assessment are identical in purpose and outcome"],a:"C",e:"Authentic Assessment COMPLEMENTS Traditional Assessment — they are not opposites but partners. Traditional = foundational knowledge (declarative/procedural). Authentic = real-world application (HOTS). Together = balanced assessment (Principle 3)."},
  {id:"aol-108",d:"moderate",t:"Reliability Methods",q:"A teacher suspects her test is too long, so she splits it into odd-numbered and even-numbered items and correlates the two halves. She is using the:",c:["A. Test-Retest Method — stability","B. Equivalent Forms Method — equivalence","C. Kuder-Richardson Method — internal consistency using proportions","D. Split-Half Method — internal consistency; test given once, split into equivalent halves"],a:"D",e:"SPLIT-HALF METHOD — measures INTERNAL CONSISTENCY. Test is given ONCE and score is equivalent halves (e.g., odd and even-numbered items). One administration, two half-test scores correlated."},
  {id:"aol-109",d:"moderate",t:"Item Analysis Interpretation",q:"An item has DI = 0.80 (Easy) and Discrimination = 0.05 (Non-discriminating). What should the teacher do?",c:["A. Retain — the difficulty index is acceptable","B. Revise — both indices are problematic (too easy AND non-discriminating)","C. Discard — non-discriminating items must always be discarded","D. Keep — non-discriminating items are acceptable for easy items"],a:"B",e:"DI = 0.80 (Easy, NOT within 0.26-0.75 = Revise or Discard) AND Discrimination = 0.05 (Non-discriminating, NOT within 0.20/0.46 = Revise). In the matrix: Neither index acceptable = REJECT/Discard."},
  {id:"aol-110",d:"moderate",t:"Validity vs. Reliability",q:"A scale consistently gives a person's weight as 5 kg MORE than their actual weight. This means the scale is:",c:["A. Valid and Reliable — it measures consistently and accurately","B. Valid but not Reliable — measures accurately but inconsistently","C. Reliable but NOT Valid — consistently measures, but does NOT measure what it intends to measure","D. Neither Valid nor Reliable"],a:"C",e:"RELIABLE (consistent — always gives same reading) but NOT VALID (does not measure what it intends to measure — weight is off by 5 kg). Reliability does not guarantee validity."},
  {id:"aol-111",d:"moderate",t:"Minor Principles of Assessment",q:"A teacher designs a test with very clear instructions: 'Answer all items. Encircle the letter of the best answer. You have 60 minutes.' Which Minor Principle of Assessment is being observed?",c:["A. Scoreability — directions for scoring are clear","B. Administrability — test is easy to administer with clear, simple, concise directions","C. Economy — test can be given cheaply","D. Interpretability — scores can be described in specific terms"],a:"B",e:"ADMINISTRABILITY — the test should be easy to administer such that the directions clearly indicate how students should respond and how much time they should spend. Clear instructions = Administrability."},
  {id:"aol-112",d:"moderate",t:"Minor Principles of Assessment",q:"A teacher uses the same scoring key consistently across all student papers, with clear points for each correct answer. This reflects which Minor Principle?",c:["A. Interpretability","B. Administrability","C. Scoreability — directions for scoring are clear; points for each correct answer are specified","D. Economy"],a:"C",e:"SCOREABILITY — test scores can be EASILY SCORED such that directions for scoring are clear and points for each correct answer is/are specified. Consistent scoring key = Scoreability."},
  {id:"aol-113",d:"moderate",t:"Kurtosis Application",q:"A teacher administers an easy quiz and finds most students scored between 90-100, but a few scored 50. The distribution is very peaked with high concentration near the top. This BEST describes:",c:["A. Platykurtic — flat and wide","B. Mesokurtic — normal, just right","C. Leptokurtic — very high peak, many scores close together, a few far away","D. Negatively skewed only, not a kurtosis issue"],a:"C",e:"LEPTOKURTIC — many scores very CLOSE TOGETHER (90-100 range), very HIGH PEAK, but SOME are very far away (50). Examples include easy quizzes where most score 90-100 but a few score 50."},
  {id:"aol-114",d:"moderate",t:"Positively Skewed Causes",q:"A teacher notices her class's scores are POSITIVELY SKEWED (skewed to the right). Which of the following is a LIKELY cause?",c:["A. Effective teaching and well-prepared students","B. Very easy test items","C. Students having enough time to finish","D. Ineffective teaching, test items were very difficult, or students were unprepared"],a:"D",e:"POSITIVELY SKEWED = most scores LOW = test was DIFFICULT. Reasons for poor performance (right-skewed): (1) ineffective teaching, (2) students' unpreparedness, (3) test items very difficult, (4) not enough time to answer."},
  {id:"aol-115",d:"moderate",t:"Assessment and Teaching",q:"A teacher uses the results of the Summative Assessment to identify which learning competencies most students failed, and redesigns her instruction accordingly. She is using assessment results for:",c:["A. Placement — to assign students to learning groups","B. Educational reform — assessment results pave the way for changes","C. Diagnostic purposes — to identify what students don't know before teaching","D. Self-assessment — students evaluating their own learning"],a:"B",e:"Summative Assessment results are powerful factors that could PAVE THE WAY FOR EDUCATIONAL REFORMS. Teachers using assessment data to redesign instruction reflects assessment's role in driving educational improvement."},
  {id:"aol-116",d:"moderate",t:"Percentile Rank Application",q:"Student A's score places her at the 75th percentile. This means:",c:["A. She answered 75% of all items correctly","B. She scored 75 out of 100","C. 75% of her classmates scored LOWER than she did, and she surpassed 75% of the class","D. She is in the top 75% of the class"],a:"C",e:"PERCENTILE RANK 75 = 75% of classmates scored BELOW her score. She SURPASSED 75% of the class and belongs to the upper 25%. (NOT the same as raw score percentage!)"},
  {id:"aol-117",d:"moderate",t:"Types of Portfolio Evidence",q:"A student's regular homework papers, class projects, and seatwork collected throughout the quarter are classified as which type of portfolio evidence?",c:["A. Reproductions — work done outside the classroom","B. Attestations — documents by teacher to attest progress","C. Artifacts — documents/products produced as a result of academic classroom work","D. Productions — documents the student prepares for themselves"],a:"C",e:"ARTIFACTS — documents or products that are produced as a RESULT of ACADEMIC CLASSROOM WORK (inside the classroom). Student papers and homework are the classic examples of artifacts."},
  {id:"aol-118",d:"moderate",t:"Types of Portfolio Evidence",q:"A student's personal goal statement, self-reflections, and captions explaining each piece of work in the portfolio are examples of:",c:["A. Artifacts — products of classroom work","B. Reproductions — outside-classroom documentation","C. Attestations — teacher's evaluative notes","D. Productions — documents that the student himself/herself prepares"],a:"D",e:"PRODUCTIONS — documents that the STUDENT HIMSELF/HERSELF PREPARES. Examples: (1) Goal statements (what the student wants to do with the portfolio), (2) Reflections (student's reflections about their work), (3) Captions (student's descriptions of each piece)."},
  {id:"aol-119",d:"moderate",t:"Matching Type Guidelines",q:"In a Matching Type test, which column should have MORE items: premises (Column A) or responses (Column B)?",c:["A. Column A (Premises) should have more items to give more options to match","B. Column B (Responses) should have MORE items than Column A — add two distractors","C. Both columns must always have equal numbers of items","D. Column A should always have exactly 10 items regardless of content"],a:"B",e:"RULE #3 — Column B (Responses/Options) must be MORE IN NUMBER than Column A (Stems/Premises) — add two more DISTRACTORS. This prevents guessing the last answer by elimination."},
  {id:"aol-120",d:"moderate",t:"Kuder-Richardson Method",q:"The KUDER-RICHARDSON METHOD of establishing reliability requires:",c:["A. Administering the test TWICE to the same group","B. Using TWO PARALLEL FORMS of the test","C. SPLITTING the test into two equivalent halves","D. Administering the test ONCE and correlating the proportion of students passing and failing each item"],a:"D",e:"KUDER-RICHARDSON — measures INTERNAL CONSISTENCY. Administer the test ONCE, then CORRELATE the proportion/percentage of students PASSING and NOT PASSING a given item. One administration, internal analysis."},
  {id:"aol-121",d:"moderate",t:"Completion Type Guidelines",q:"A teacher writes this completion item: 'The ____ from the ____ that captures ____ from the ____ is called the ____.' This violates which rule?",c:["A. Rule #2 — Avoid open-ended items with multiple correct answers","B. Rule #4 — Make blanks uniform in size","C. Rule #1 — Avoid overmutelating sentences (too many blanks per item)","D. Rule #3 — Blank should be near the end"],a:"C",e:"RULE #1 — Avoid OVERMUTILATED SENTENCES (too many blanks per item — one blank, one answer). The example has FIVE blanks — it becomes too confusing and difficult to answer logically."},
  {id:"aol-122",d:"moderate",t:"Completion Type Guidelines",q:"A teacher writes: 'An example of a mammal is ___.' This completion item violates which rule?",c:["A. Rule #1 — Too many blanks","B. Rule #2 — Avoid open-ended items; there should be only ONE acceptable answer","C. Rule #3 — Blank should be at the end","D. Rule #4 — Blanks must be uniform in size"],a:"B",e:"RULE #2 — Avoid OPEN-ENDED items. There should be ONLY ONE ACCEPTABLE ANSWER. 'An example of a mammal' has many correct answers (whale, dog, cat, human) — not appropriate for a completion item."},
  {id:"aol-123",d:"moderate",t:"Normal Distribution",q:"In a Normal Distribution, the curve has FOUR key properties. Which of the following is NOT a property of the Normal Distribution?",c:["A. The curve has a single peak — unimodal","B. It is bell-shaped and symmetrical to the mean","C. The end tails can be extended indefinitely in both sides","D. The mean is always greater than the median in a normal distribution"],a:"D",e:"In a NORMAL DISTRIBUTION: Mean = Median = Mode. The statement 'mean is always greater than median' describes a POSITIVELY SKEWED distribution, NOT normal distribution. The four properties: unimodal, bell-shaped, symmetrical, tails extend indefinitely."},
  {id:"aol-124",d:"moderate",t:"Z-Score Application",q:"Mark scored 95 in Math (Mean=93, SD=10), 92 in Labor Management (Mean=90, SD=4), and 80 in Natural Science (Mean=85, SD=5). In which subject did he perform BEST relative to his class?",c:["A. Mathematics — highest raw score","B. Labor Management — Z-score is highest","C. Natural Science — lowest raw score shows most room for improvement","D. All subjects equally — the Z-scores are all the same"],a:"B",e:"Math Z = (95-93)/10 = 0.2. Labor Mgt Z = (92-90)/4 = 0.5. Nat Sci Z = (80-85)/5 = -1.0. LABOR MANAGEMENT has the HIGHEST Z-SCORE (0.5) → Mark performed best RELATIVE TO HIS CLASS in Labor Management."},
  {id:"aol-125",d:"moderate",t:"Grading System",q:"Under DepEd Order 8 s.2015 (K-12 Grading System), the assessment is classified into three components. Which of the following is the DOMINANT component with the HIGHEST WEIGHT?",c:["A. Written Works — highest weight because it develops writing skills","B. Quarterly Assessment — highest weight because it covers all topics","C. Performance Tasks — highest weight because it requires application of skills","D. The weighting depends on the subject area and grade level"],a:"D",e:"Under the K-12 Grading System, the weights of Written Works, Performance Tasks, and Quarterly Assessment VARY by subject area. For example, MAPEH gives more weight to Performance Tasks, while Math and Science distribute weights differently."},
  {id:"aol-126",d:"moderate",t:"Assessment Misconceptions",q:"A teacher says 'A valid test is always reliable.' A colleague disagrees. Who is correct?",c:["A. The teacher is correct — validity guarantees reliability","B. The colleague is correct — a valid test may NOT always be reliable","C. Both are partially correct — validity and reliability are identical","D. Neither — validity and reliability are unrelated concepts in assessment"],a:"B",e:"A VALID test is not necessarily RELIABLE. If a test measures what it intends but gives inconsistent scores (due to poor item construction or random guessing), it is valid but unreliable. HOWEVER, a reliable test is NOT necessarily valid."},
  {id:"aol-127",d:"moderate",t:"Assessment Misconceptions",q:"A test that consistently gives WRONG measurements (e.g., always 10 points too high) is:",c:["A. Both Valid and Reliable — it is consistent","B. Reliable but NOT Valid — consistent but does not measure what it should","C. Valid but NOT Reliable — measures what it should but inconsistently","D. Neither Valid nor Reliable — it is wrong and inconsistent"],a:"B",e:"A test that CONSISTENTLY gives wrong measurements = RELIABLE (consistent) but NOT VALID (does not give accurate/correct measurement). Consistency ≠ Accuracy."},
  {id:"aol-128",d:"moderate",t:"Skewness Causes",q:"A teacher's class produces a NEGATIVELY SKEWED distribution. Which of the following is a LIKELY reason?",c:["A. Ineffective teaching — students are not learning","B. Test items are very difficult — most students can't answer","C. Students are smart, test is easy, effective instruction, or students prepared well","D. Students did not have enough time to finish the test"],a:"C",e:"NEGATIVELY SKEWED = most scores HIGH = test was EASY or students performed well. Possible reasons: (1) Students are smart, (2) Enough time to finish, (3) Test items very easy, (4) Effective instruction, (5) Students prepared."},
  {id:"aol-129",d:"moderate",t:"Platykurtic",q:"A teacher gives a very difficult exam covering a wide range of abilities. Scores range from 40 to 95, with some students doing very well, some struggling, and many in between. This distribution is BEST described as:",c:["A. Leptokurtic — tall, narrow, very peaked","B. Mesokurtic — normal bell curve","C. Platykurtic — flat, wide, scores spread out, no big group in the middle","D. Positively Skewed — most scores are low"],a:"C",e:"PLATYKURTIC — scores are SPREAD OUT, NO BIG GROUP in the middle, distribution LOOKS FLAT. Hard exam with wide range of scores (40-95) and different ability levels spread throughout = platykurtic."},
  {id:"aol-130",d:"moderate",t:"Stanines Application",q:"A student receives a stanine score of 2. What does this indicate about the student's performance?",c:["A. Very High — at the top of the group","B. Average — typical performance","C. Above Average — slightly better than most","D. Below Average — performance is lower than most of the group"],a:"D",e:"STANINE 2 = BELOW AVERAGE. Stanine categories: 1=Very Low, 2-3=Below Average, 4-6=Average, 7-8=Above Average, 9=Very High. Stanine 2 is clearly Below Average."},
  {id:"aol-131",d:"moderate",t:"Measures of Variability Interpretation",q:"Class A has scores with SD=2. Class B has scores with SD=15. What does this DIFFERENCE indicate?",c:["A. Class A performed better than Class B on the same test","B. Class B performed better than Class A","C. Class A scores are CLOSELY CLUSTERED (small variability); Class B scores are MORE DISPERSED (large variability)","D. Class A has more students than Class B"],a:"C",e:"SMALL SD (Class A=2) = scores are CLOSELY CLUSTERED, HOMOGENEOUS, less varied — students performed similarly. LARGE SD (Class B=15) = scores are DISPERSED, SCATTERED, HETEROGENEOUS — wide range of performance."},
  {id:"aol-132",d:"moderate",t:"Assessment of Learning Tools",q:"Scoring rubrics are essential for essay tests, student products, and performance tasks because objective tests can be scored by simply counting correct answers, but these tasks:",c:["A. Are less important than objective tests in measuring learning","B. Can be scored reliably ONLY with the use of scoring rubrics","C. Should not be used in the classroom due to subjectivity","D. Can be scored using multiple choice answer keys"],a:"B",e:"Essay tests, student products, and performances CANNOT be scored the way objective tests are scored. They can be scored RELIABLY only with the use of SCORING RUBRICS — making rubrics essential for authentic assessment."},
  {id:"aol-133",d:"moderate",t:"Completion Type",q:"Which guideline states that the blank in a Completion item should be placed at the END OR NEAR THE END of the sentence?",c:["A. Rule #1 — Avoid overmutelating sentences","B. Rule #2 — Avoid open-ended items","C. Rule #3 — The blank should be at the end or near the end of the sentence","D. Rule #4 — Make blanks uniform in size"],a:"C",e:"RULE #3 — The BLANK should be at the END or NEAR THE END of the sentence, rather than at the beginning. This allows students to read the full context before encountering the blank."},
  {id:"aol-134",d:"moderate",t:"Multiple Choice Guidelines",q:"A teacher writes a stem that reveals the answer to another item on the same test. This violates:",c:["A. Rule #2 — Avoid vague modifiers","B. Rule #3 — Avoid complex word arrangements","C. Rule #5 — Grammatical consistency","D. Rule #6 — Avoid stems that reveal the answer to another item"],a:"D",e:"RULE #6 — Avoid STEMS THAT REVEAL THE ANSWER to another item. If item 5's stem contains information that gives away the answer to item 12, the test is flawed and unfair."},
  {id:"aol-135",d:"moderate",t:"Criterion-related Validity",q:"A school uses an entrance exam to predict which students will succeed in the program. They compare entrance exam scores with students' grade point averages at the END of the school year. This represents:",c:["A. Concurrent Validity — two measures given at the same time","B. Content Validity — checking curricular objectives","C. Face Validity — checking physical appearance","D. Predictive Validity — predicting future performance through correlation at a longer time interval"],a:"D",e:"PREDICTIVE VALIDITY — describes FUTURE PERFORMANCE by correlating scores from two measures at a LONGER TIME INTERVAL. Entrance exam → End-of-year GPA = Predictive Validity."},
  {id:"aol-136",d:"moderate",t:"Assessment FOR Learning",q:"Which of the following BEST distinguishes Assessment FOR Learning from Assessment OF Learning?",c:["A. Assessment FOR Learning is more important than Assessment OF Learning","B. Assessment FOR Learning is done during and before instruction to improve teaching and learning; Assessment OF Learning is done after instruction to evaluate outcomes and assign grades","C. Assessment OF Learning includes formative and diagnostic; Assessment FOR Learning is only summative","D. Both types of assessment are identical in purpose — they differ only in timing"],a:"B",e:"Assessment FOR Learning = Placement + Diagnostic + Formative = BEFORE and DURING instruction = improve teaching/learning. Assessment OF Learning = Summative = AFTER instruction = evaluate outcomes and assign grades."},
  {id:"aol-137",d:"moderate",t:"Kuder-Richardson vs. Split-Half",q:"Both the Kuder-Richardson and Split-Half methods measure INTERNAL CONSISTENCY. The KEY difference is:",c:["A. Kuder-Richardson requires two test administrations; Split-Half requires only one","B. Split-Half divides the test into two halves and correlates them; Kuder-Richardson correlates the proportion of students passing and failing each individual item","C. Both methods give identical results — there is no meaningful difference","D. Kuder-Richardson is for essay tests; Split-Half is for multiple choice tests"],a:"B",e:"SPLIT-HALF: divides test into two halves (odd/even), correlates the two half-test scores. KUDER-RICHARDSON: Given once, correlates the proportion/percentage of students PASSING and NOT PASSING each individual item."},
  {id:"aol-138",d:"moderate",t:"Reliability",q:"A test is given to the same group of students in October and again in February. The scores from both administrations are then correlated. This is the:",c:["A. Equivalent Forms Method","B. Split-Half Method","C. Kuder-Richardson Method","D. Test-Retest Method — stability; same test, same group, different time points"],a:"D",e:"TEST-RETEST METHOD — SAME TEST, SAME GROUP, given TWICE with a TIME INTERVAL between administrations (from several minutes to several years). Measures STABILITY of the test."},
  {id:"aol-139",d:"moderate",t:"Essay Guidelines",q:"Essay Rule #5 states: 'Whenever possible, have TWO OR MORE PERSONS GRADE each answer.' This is primarily to:",c:["A. Save time by dividing the grading workload","B. Avoid bias — multiple graders reduce the effect of any single grader's subjectivity","C. Ensure different scoring criteria are applied to the same essay","D. Allow different graders to apply different rubrics to the same answer"],a:"B",e:"RULE #5 — TWO OR MORE PERSONS GRADE each answer to AVOID BIAS. A single grader's subjectivity, preferences, or fatigue can affect scores. Multiple graders using the same rubric = more reliable, less biased scores."},
  {id:"aol-140",d:"moderate",t:"Assessment Principles",q:"PRINCIPLE 5 (RELIABILITY) and PRINCIPLE 4 (VALIDITY) are both important for assessment. Which statement CORRECTLY expresses their relationship?",c:["A. A test can be valid without being reliable, and reliable without being valid","B. A reliable test is automatically valid; validity implies reliability","C. Validity is the most important criterion; a valid test is always reliable but a reliable test may NOT always be valid","D. Reliability and validity refer to the same concept — they are interchangeable"],a:"C",e:"VALIDITY is the MOST IMPORTANT criterion. A VALID test is always reliable (measures accurately + consistently). However, a RELIABLE test is NOT always valid (consistent measurement that may not measure what it should). Validity > Reliability."},
  {id:"aol-141",d:"moderate",t:"Portfolio Evidence",q:"A student asks a community leader to write a letter attesting to her leadership role in the barangay youth council. This letter, placed in the portfolio, is an example of:",c:["A. Artifact — product of academic classroom work","B. Reproduction — documentation of work outside the classroom","C. Attestation — documentation by a responsible person attesting to the student's progress","D. Production — document that the student herself prepares"],a:"C",e:"ATTESTATION — the TEACHER or OTHER RESPONSIBLE PERSONS' documentation to ATTEST to the student's progress. A community leader's letter about leadership performance = attestation by a responsible person outside school."},
  {id:"aol-142",d:"moderate",t:"Mean Computation",q:"Ten Grade 10 students got: 70, 72, 75, 77, 78, 80, 84, 87, 90, 92. What is the MEAN?",c:["A. 78.5","B. 80.5","C. 78","D. 79"],a:"B",e:"Sum = 70+72+75+77+78+80+84+87+90+92 = 805. Mean = 805 ÷ 10 = 80.5."},
  {id:"aol-143",d:"moderate",t:"Median Computation",q:"Find the MEDIAN of these 9 scores arranged in ascending order: 14, 35, 45, 55, 56, 65, 87, 89, 92.",c:["A. 55","B. 55.5","C. 56","D. 65"],a:"C",e:"9 scores (ODD number). Median = middle score = the 5th score. Arranged: 14, 35, 45, 55, 56, 65, 87, 89, 92. The 5th score = 56. Median = 56."},
  {id:"aol-144",d:"moderate",t:"Bimodal Distribution",q:"These scores: 25, 24, 24, 20, 20, 20, 16, 12, 10, 7. What is/are the MODE/S?",c:["A. Mode = 20 only (unimodal)","B. Mode = 24 only","C. Mode = 20 and 24 (bimodal)","D. No mode exists"],a:"C",e:"24 appears 2 times. 20 appears 3 times. Wait — actually: 24 appears 2 times and 20 appears 3 times. Mode = 20 (appears most). BUT looking again: 25,24,24,20,20,20 → 20 appears 3 times, 24 appears 2 times. Mode = 20. However if equalized: 20 (3 times) is the sole mode. Mode = 20 ONLY (unimodal). Answer: A"},
  {id:"aol-145",d:"moderate",t:"Discrimination Index Computation",q:"Item X was answered correctly by 18 out of 20 upper group students and 6 out of 20 lower group students. What is the Discrimination Index?",c:["A. D = 0.30","B. D = 0.40","C. D = 0.50","D. D = 0.60"],a:"D",e:"DU = 18/20 = 0.90; DL = 6/20 = 0.30. D = DU - DL = 0.90 - 0.30 = 0.60. Range 0.46-1.0 = DISCRIMINATING ITEM = Include."},
  {id:"aol-146",d:"moderate",t:"Positive Discrimination",q:"POSITIVE DISCRIMINATION in Item Analysis occurs when:",c:["A. The proportion of students in the lower group who got an item right is GREATER than the upper group","B. The proportion of upper group students who got an item right EQUALS the lower group proportion","C. The proportion of upper group students who got an item right is GREATER than the lower group","D. Both groups answered the item incorrectly"],a:"C",e:"POSITIVE DISCRIMINATION — the proportion of students who got an item right in the UPPER GROUP is GREATER THAN the LOWER GROUP. DU > DL → D is POSITIVE → good discriminating item."},
  {id:"aol-147",d:"moderate",t:"Zero Discrimination",q:"ZERO DISCRIMINATION occurs when:",c:["A. The upper group performs better than the lower group on an item","B. The lower group performs better than the upper group","C. Both upper and lower groups answered equally — DU = DL","D. Nobody in either group answered the item correctly"],a:"C",e:"ZERO DISCRIMINATION — the proportion of students who got the item right in the upper group EQUALS the proportion in the lower group (DU = DL). The item does not distinguish between high and low performers."},
  {id:"aol-148",d:"moderate",t:"Negative Discrimination",q:"NEGATIVE DISCRIMINATION occurs when:",c:["A. DU > DL — upper group performs better","B. DU = DL — equal performance between groups","C. DL > DU — lower group performs BETTER than the upper group","D. Both groups scored 0 on the item"],a:"C",e:"NEGATIVE DISCRIMINATION — the proportion of students who got the item right in the LOWER GROUP is GREATER THAN the upper group (DL > DU). This is problematic — high performers are getting it wrong more than low performers."},
  {id:"aol-149",d:"moderate",t:"Assessment AS Learning",q:"Which of the following BEST explains why Assessment AS Learning helps students become 'self-directed and independent learners'?",c:["A. Because it is done by the teacher after instruction to assign grades","B. Because students passively receive feedback from the teacher","C. Because students SET THEIR OWN TARGETS, ACTIVELY MONITOR, and EVALUATE their own learning — building metacognitive skills","D. Because it provides placement information before instruction begins"],a:"C",e:"Assessment AS Learning builds metacognition — students set targets, monitor their own learning, and evaluate themselves. This active self-regulation makes them self-directed and independent learners."},
  {id:"aol-150",d:"moderate",t:"Table of Specifications",q:"Content Validity is closely related to the TABLE OF SPECIFICATIONS (TOS). A TOS ensures that:",c:["A. The test is easy to administer","B. Test items are consistent grammatically","C. Test items are proportionally distributed across all learning objectives covered — the test reflects the curriculum","D. Test items are arranged from easiest to hardest"],a:"C",e:"The TOS ensures CONTENT VALIDITY — that test items are proportionally distributed across all learning objectives and content taught. A test with a TOS reflects the CURRICULAR OBJECTIVES and is content-valid."},
  {id:"aol-151",d:"moderate",t:"Measures of Central Tendency Application",q:"A teacher wants to report the 'average' performance of the class but the data has several extreme high scores from exceptional students. She should use the:",c:["A. Mean — highest reliability and used for computing standard deviation","B. Mode — most frequently occurring score","C. Median — not affected by extreme scores; better with skewed data","D. Range — shows the spread of scores"],a:"C",e:"When there are EXTREME SCORES (outliers), the MEDIAN is preferred because it is NOT affected by extreme scores — it is a POSITIONAL measure. The mean would be inflated by the extreme high scores."},
  {id:"aol-152",d:"moderate",t:"When to Use the Mean",q:"Which situation MOST CALLS for the use of the MEAN as the measure of central tendency?",c:["A. When there are a few very high or very low scores that could distort the average","B. When data is qualitative (non-numerical categories)","C. When it is desired to give each score equal weight, find the highest reliability measure, or compute Standard Deviation later","D. When the distribution is strongly skewed"],a:"C",e:"Use the MEAN when: (1) each score should have equal weight, (2) you need the measure with highest reliability, and (3) you will compute the standard deviation and coefficient of correlation later."},
  {id:"aol-153",d:"moderate",t:"Assessment and K-12",q:"Under the K-12 curriculum, the assessment system is guided by DepEd Order 8, s.2015. The three components of assessment are:",c:["A. Diagnostic, Formative, and Summative","B. Written Works, Performance Tasks, and Quarterly Assessment","C. Traditional, Authentic, and Portfolio Assessment","D. For Learning, Of Learning, and As Learning"],a:"B",e:"Under the K-12 Grading System (DepEd Order 8 s.2015), the three assessment components are: (1) WRITTEN WORKS, (2) PERFORMANCE TASKS, and (3) QUARTERLY ASSESSMENT — with different weights per subject."},
  {id:"aol-154",d:"moderate",t:"True-False Rule Application",q:"A True-False item reads: 'The changes that take place early in childhood are NOT UNchangeable.' This violates which rule?",c:["A. Rule #2 — Avoid sweeping terms","B. Rule #3 — Avoid long sentences","C. Rule #7 — Avoid double negatives ('not' + 'un') as they are confusing","D. Rule #6 — Avoid disproportionate numbers of true or false statements"],a:"C",e:"RULE #7 — Avoid DOUBLE NEGATIVES as they tend to be confusing. 'NOT UNchangeable' = double negative = confusing. Students may answer based on language parsing rather than content knowledge."},
  {id:"aol-155",d:"moderate",t:"Discrimination Index Interpretation",q:"An item has a Discrimination Index of -0.60. What does this mean and what action should be taken?",c:["A. Excellent item — very high discrimination, include in the test","B. Good item — positive discrimination, retain","C. Questionable item — CAN discriminate but in the WRONG direction (lower group got it right more often); DISCARD","D. Non-discriminating item — revise and improve distractors"],a:"C",e:"D = -0.60 is in the range of -1.0 to -0.56 = CAN DISCRIMINATE but ITEM IS QUESTIONABLE (negative discrimination = lower group performed better = suspicious). Action: DISCARD."},
  {id:"aol-156",d:"moderate",t:"Z-Score Comparison",q:"Which of the following Z-scores represents the HIGHEST relative performance?",c:["A. Z = -2.5","B. Z = -0.5","C. Z = 0.0","D. Z = +1.8"],a:"D",e:"The HIGHEST Z-SCORE represents the best performance RELATIVE TO THE CLASS. Z = +1.8 is the highest (1.8 standard deviations ABOVE the mean). Z = 0 = exactly at the mean. Z = -2.5 = very far below the mean."},
  {id:"aol-157",d:"moderate",t:"Median When n is Even",q:"Find the MEDIAN of: 14, 35, 45, 55, 55, 56, 65, 87, 89, 92 (n=10, even number).",c:["A. 55","B. 55.5","C. 56","D. 57"],a:"B",e:"When n is EVEN, median = average of the two MIDDLE SCORES. n=10, so middle positions = 5th and 6th. 5th score = 55, 6th score = 56. Median = (55+56)/2 = 55.5."},
  {id:"aol-158",d:"moderate",t:"Mesokurtic",q:"A normal Quiz where most students get 75-85, a normal bell curve shape. This is BEST described as:",c:["A. Leptokurtic — very peaked","B. Platykurtic — very flat","C. Mesokurtic — scores are just right, normal bell shape, most are average","D. Positively Skewed — most scores are low"],a:"C",e:"MESOKURTIC — scores are JUST RIGHT, MOST ARE AVERAGE. Normal bell curve. Not too high/not too low. Example: Most students get 75-85 on a normal quiz. This is the 'just normal' kurtosis."},
  {id:"aol-159",d:"moderate",t:"Assessment Components Weight",q:"Under the K-12 Grading System, the component with the HIGHEST WEIGHT in MAPEH (Music, Arts, Physical Education, and Health) is:",c:["A. Written Works — because knowledge is primary in MAPEH","B. Quarterly Assessment — because it covers all topics learned","C. Performance Tasks — because MAPEH is primarily skills and performance-based","D. Portfolio Assessment — because it shows student progress over time"],a:"C",e:"In MAPEH, PERFORMANCE TASKS has the highest weight because MAPEH is primarily about SKILLS and PERFORMANCE. Students demonstrate learning through actual performance rather than written knowledge."},
  {id:"aol-160",d:"moderate",t:"Item Analysis Decision Matrix",q:"An item with DI within 0.26-0.75 AND Discrimination Index of 0.20 and above should be:",c:["A. Rejected — the difficulty index doesn't matter","B. Revised — even good difficulty needs revision","C. RETAINED — both the difficulty index is right AND discrimination is acceptable","D. Discarded — unless the discrimination exceeds 0.46"],a:"C",e:"RETAIN when: DI within 0.26-0.75 (Right Difficulty) AND Discrimination within 0.20 and above. Both criteria met = RETAIN the item. This is the ideal combination."},

  // ==================== DIFFICULT (40) ====================
  {id:"aol-161",d:"difficult",t:"Integrated Assessment Concepts",q:"A teacher gives a pretest (finding students know 30% of content), teaches, administers exit tickets daily, and gives a final exam. The pretest, exit tickets, and final exam serve which assessment purposes RESPECTIVELY?",c:["A. Summative, Diagnostic, Formative","B. Formative, Summative, Diagnostic","C. Diagnostic, Formative, Summative","D. Placement, Diagnostic, Summative"],a:"C",e:"PRETEST = DIAGNOSTIC (what do students already know BEFORE instruction?). EXIT TICKETS = FORMATIVE (ongoing feedback DURING instruction). FINAL EXAM = SUMMATIVE (evaluation AFTER instruction). Classic sequence: Diagnostic → Formative → Summative."},
  {id:"aol-162",d:"difficult",t:"Validity vs. Reliability",q:"A bathroom scale consistently shows '5 kg heavier' than actual weight for ALL users. Another scale gives randomly different readings for the same person. Which of the following CORRECTLY characterizes each?",c:["A. Scale 1: Valid and Reliable; Scale 2: Valid but not Reliable","B. Scale 1: Reliable but not Valid; Scale 2: Neither Valid nor Reliable","C. Scale 1: Valid but not Reliable; Scale 2: Reliable but not Valid","D. Both scales have equivalent validity and reliability issues"],a:"B",e:"Scale 1: RELIABLE (consistently +5 kg = same result every time) but NOT VALID (does not measure true weight = wrong). Scale 2: NEITHER Valid NOR Reliable (random readings = inconsistent AND wrong)."},
  {id:"aol-163",d:"difficult",t:"Item Analysis Advanced",q:"A teacher has a 50-item test. She computes DI and D for all items. Item 23 has DI=0.30 (right difficulty) and D=0.18 (non-discriminating). Item 24 has DI=0.20 (difficult) and D=0.55 (discriminating). What should she do with each item?",c:["A. Retain both — both have at least one good index","B. Revise Item 23; Revise Item 24","C. Revise Item 23 (good DI but poor discrimination); Revise Item 24 (poor DI but good discrimination)","D. Discard Item 23; Retain Item 24"],a:"C",e:"Item 23: DI=0.30 ✓ (within 0.26-0.75) but D=0.18 ✗ (below 0.20) → one good, one bad = REVISE. Item 24: DI=0.20 ✗ (below 0.26) but D=0.55 ✓ (above 0.46) → one good, one bad = REVISE. BOTH items need revision."},
  {id:"aol-164",d:"difficult",t:"Z-Score and T-Score Application",q:"In three subjects: Math (mean=93, SD=10, score=95), Science (mean=85, SD=5, score=80), Filipino (mean=90, SD=4, score=92). In which subject did the student perform POOREST relative to class?",c:["A. Math — raw score closest to mean","B. Science — Z-score is the most negative","C. Filipino — smallest raw score margin above mean","D. Math — the standard deviation is largest, diluting performance"],a:"B",e:"Math Z=(95-93)/10=0.2. Science Z=(80-85)/5=-1.0. Filipino Z=(92-90)/4=0.5. SCIENCE has the MOST NEGATIVE Z-SCORE (-1.0) = student performed POOREST relative to class in Science — 1 SD BELOW the class mean."},
  {id:"aol-165",d:"difficult",t:"Integrated Statistics",q:"A class has scores: Mean=75, Median=70, Mode=65. A teacher must correctly interpret this distribution. Which interpretation is MOST ACCURATE?",c:["A. The distribution is normal since mean, median, and mode are present","B. The distribution is negatively skewed — Mode > Median > Mean — most scores are high","C. The distribution is positively skewed — Mean > Median > Mode — thin tail goes RIGHT, most scores are LOW","D. The distribution is bimodal — two peaks are present"],a:"C",e:"Mean (75) > Median (70) > Mode (65) = POSITIVELY SKEWED. Thin tail goes to the RIGHT. Most scores are LOW (below mean). The test was likely DIFFICULT. (PRDL: Positive=Right=Difficult=Low)"},
  {id:"aol-166",d:"difficult",t:"Assessment Design",q:"A teacher is designing an end-of-unit assessment for Science. She wants it to be valid, reliable, balanced, and authentic. Which combination BEST meets ALL these criteria?",c:["A. 50 True-False items covering all objectives","B. A single extended essay covering only the hardest topic","C. A combination of: (1) an objective test covering all learning objectives (validity/content coverage) and (2) a performance task with an analytic rubric (authentic, balanced) — scored consistently (reliability)","D. An oral interview of a random sample of students"],a:"C",e:"Best assessment design: Objective test (content validity — covers all objectives) + Performance task with analytic rubric (authentic, balanced, reliable scoring). This satisfies Principles 1-5: Clear targets, appropriate methods, balanced, valid, and reliable."},
  {id:"aol-167",d:"difficult",t:"Skewness and Remediation",q:"A teacher reviews final exam results and finds: Mean=55, Median=60, Mode=65. The distribution is positively skewed. What is the MOST APPROPRIATE instructional response?",c:["A. No action needed — the distribution is normal","B. Celebrate! Most students scored high — the distribution indicates excellence","C. Review and remediate — most scores are LOW (below mean), suggesting the test was difficult or instruction was ineffective","D. Redesign the test — the skewness indicates faulty test construction only"],a:"C",e:"POSITIVELY SKEWED = most scores LOW = poor performance (Mean < Median < Mode = right tail). Teacher should REVIEW AND REMEDIATE — identify why students performed poorly (test too difficult? Instruction ineffective? Students unprepared?)."},
  {id:"aol-168",d:"difficult",t:"Assessment Ethics",q:"A teacher grades essay tests while aware of each student's name and previous performance. This practice VIOLATES which assessment principle/guideline?",c:["A. Principle 1 — Clear Learning Targets","B. Essay Rule #4 — Evaluate answers WITHOUT KNOWING THE IDENTITY OF THE WRITER to avoid bias","C. Principle 3 — Balance across all domains","D. Minor Principle — Economy of time and resources"],a:"B",e:"Essay RULE #4 — Evaluate answers WITHOUT KNOWING THE IDENTITY OF THE WRITER to AVOID BIAS. Prior knowledge of the student (high achiever vs. struggling) can unconsciously bias the grader's judgment."},
  {id:"aol-169",d:"difficult",t:"Portfolio Design",q:"A school requires ALL teachers to use portfolios as part of their assessment. A critic argues: 'Portfolios alone are insufficient for Assessment OF Learning because they primarily serve Assessment FOR and AS Learning purposes.' The MOST DEFENSIBLE response is:",c:["A. Portfolios are sufficient for all assessment purposes including grading","B. The critic is CORRECT — portfolios primarily serve formative and self-assessment purposes; summative (OF Learning) still requires a combination of methods including objective tests and formal evaluations","C. Portfolios replace all other forms of assessment — traditional testing is obsolete","D. The critic is wrong — portfolios are the most comprehensive assessment tool available"],a:"B",e:"The critic is correct — portfolios primarily serve Assessment FOR (documenting growth) and AS (self-reflection) Learning. Summative Assessment (OF Learning) for grading purposes needs objective tests and formal evaluations. BALANCE (Principle 3) requires multiple methods."},
  {id:"aol-170",d:"difficult",t:"Integrated Item Analysis",q:"A test item has DI=0.10 and D=-0.30. What action is recommended AND why?",c:["A. Retain — at least one index is within range","B. Revise — DI is poor but D is acceptable","C. DISCARD — DI is 0-0.25 (Difficult/Revise or Discard) AND D is -1.0 to -0.56 (Can discriminate but questionable) = both indicate the item is seriously flawed","D. Revise only the distractors — the stem is acceptable"],a:"C",e:"DI=0.10 (below 0.26 = Difficult = Revise or Discard) AND D=-0.30 (within -1.0 to -0.56 = Negative discrimination = questionable = DISCARD). Item is difficult AND negatively discriminating (lower group got it right more) = DISCARD."},
  {id:"aol-171",d:"difficult",t:"Reliability Methods Comparison",q:"A test designer wants to measure whether TWO DIFFERENT FORMS of the same test are EQUALLY DIFFICULT over a LONGER TIME INTERVAL. Which reliability method BEST fits this purpose?",c:["A. Test-Retest — same test, twice, measures stability only","B. Equivalent Forms Method — parallel tests, close time interval, equivalence only","C. Test-Retest with Equivalent Forms — parallel tests, INCREASED time interval, measures BOTH stability AND equivalence","D. Kuder-Richardson — one administration, internal consistency"],a:"C",e:"TEST-RETEST WITH EQUIVALENT FORMS = measures BOTH STABILITY AND EQUIVALENCE. Gives PARALLEL FORMS of tests with an INCREASED time interval between forms. Best when you need both stability (over time) and equivalence (across forms)."},
  {id:"aol-172",d:"difficult",t:"Assessment and Learning",q:"A researcher finds that students in classrooms using Assessment AS Learning (peer and self-assessment with rubrics) outperform students in traditional-only assessment classrooms on both performance tasks AND standardized tests. What theoretical explanation BEST accounts for this finding?",c:["A. Self-assessment wastes time that should be used for instruction","B. Assessment AS Learning develops METACOGNITIVE skills — students learn to monitor, regulate, and improve their own learning, which transfers to all assessment formats","C. Traditional assessment is inferior to all forms of portfolio assessment","D. Standardized tests are inherently biased against students from traditional classrooms"],a:"B",e:"Assessment AS Learning builds METACOGNITION — students who can monitor, evaluate, and regulate their own learning become more effective learners across all contexts. This metacognitive advantage transfers to improved performance on all assessment types."},
  {id:"aol-173",d:"difficult",t:"Validity Advanced",q:"A new teacher-made vocabulary test for Grade 5 students correlates strongly with an established, validated vocabulary test for Grade 5. This evidence MOST directly supports which type of validity for the new test?",c:["A. Face Validity — physical appearance suggests it measures vocabulary","B. Content Validity — objectives are covered","C. Concurrent Validity — the new test correlates with another established measure given concurrently","D. Predictive Validity — predicts future vocabulary performance"],a:"C",e:"CONCURRENT VALIDITY — the new test is correlated with an already established, validated test given AT THE SAME TIME (concurrently). High correlation = the new test measures the same construct (vocabulary) as the established test."},
  {id:"aol-174",d:"difficult",t:"Statistics Integration",q:"Class A: Mean=80, SD=2. Class B: Mean=80, SD=15. Both classes take the SAME test. Teacher A says 'Both classes performed equally well.' Teacher B says 'The classes have very different score patterns.' Who is correct and why?",c:["A. Teacher A is correct — same mean = same performance","B. Teacher B is correct — same mean but VERY DIFFERENT variability. Class A is homogeneous (scores clustered near 80); Class B is heterogeneous (wide spread — some very high, some very low)","C. Both are equally correct — mean and SD provide no meaningful comparison","D. Teacher A is correct because the mean is the most important statistic"],a:"B",e:"SAME MEAN but DIFFERENT SD. Class A (SD=2): scores TIGHTLY CLUSTERED near 80 = homogeneous. Class B (SD=15): scores WIDELY DISPERSED = heterogeneous. The MEAN alone is insufficient — VARIABILITY reveals the DISTRIBUTION PATTERN."},
  {id:"aol-175",d:"difficult",t:"Authentic vs. Traditional",q:"A critic argues: 'Authentic Assessment should REPLACE Traditional Assessment because it is more meaningful and real-world relevant.' The STRONGEST counter-argument is:",c:["A. Traditional Assessment is always more objective than Authentic Assessment","B. Authentic Assessment is too subjective and cannot be scored reliably","C. Both types COMPLEMENT each other (not compete) — Traditional Assessment efficiently measures foundational knowledge; Authentic Assessment measures real-world application. BALANCE (Principle 3) requires BOTH","D. Traditional Assessment is more valid because it can be standardized"],a:"C",e:"Authentic Assessment COMPLEMENTS Traditional Assessment — they are not competitors. Traditional = foundational knowledge. Authentic = real-world application. Principle 3 (BALANCED) explicitly requires BOTH types for a comprehensive picture of learning."},
  {id:"aol-176",d:"difficult",t:"Normal Distribution Advanced",q:"In a normal distribution with Mean=70 and SD=10, a student scored 90. What is the student's percentile rank, approximately?",c:["A. About 84th percentile — 1 SD above the mean","B. About 97.72nd percentile — 2 SD above the mean","C. About 99.86th percentile — 3 SD above the mean","D. About 75th percentile — above average but not at 2 SD"],a:"B",e:"Score 90 = Mean + 2SD (70 + 2×10 = 90). Within ±2 SD = 95.44% of scores. Below +2 SD = 50% + 47.72% = 97.72%. So approximately the 97.72nd percentile — student scored higher than about 97.72% of the group."},
  {id:"aol-177",d:"difficult",t:"Assessment Design Advanced",q:"A teacher wants her assessment to be RELIABLE. She notices her essay scores vary widely between grading sessions (she scores the same essay 72 one day and 85 another day). The BEST solution to this reliability problem is:",c:["A. Use only True-False items to eliminate subjectivity","B. Develop and consistently apply a detailed ANALYTIC RUBRIC — reduces subjective variation by specifying clear criteria and performance level descriptors","C. Have students self-grade their own essays","D. Give the essay to multiple students to decrease individual differences"],a:"B",e:"Scoring essays RELIABLY requires a detailed ANALYTIC RUBRIC. Without rubric criteria, scores vary based on mood, fatigue, or bias. An analytic rubric provides consistent, criterion-referenced scoring across grading sessions, increasing reliability."},
  {id:"aol-178",d:"difficult",t:"Item Analysis Advanced Computation",q:"40 students take a test. Upper 27% = 11 students; lower 27% = 11 students. On Item 5: upper group = 9 correct; lower group = 3 correct. What is the DI of Item 5 (for the upper group) and the Discrimination Index?",c:["A. DI(upper) = 0.27; D = 0.50","B. DI(upper) = 0.82; D = 0.55","C. DI(upper) = 0.75; D = 0.48","D. DI(upper) = 0.70; D = 0.40"],a:"B",e:"DU = 9/11 = 0.818 ≈ 0.82. DL = 3/11 = 0.273 ≈ 0.27. D = DU - DL = 0.82 - 0.27 = 0.55. Discrimination Index = 0.55 (0.46-1.0 range = DISCRIMINATING = Include)."},
  {id:"aol-179",d:"difficult",t:"Kurtosis and Skewness Integration",q:"A test produces a distribution that is BOTH Negatively Skewed AND Leptokurtic. What does this tell the teacher about student performance and the test?",c:["A. Most scores are LOW and clustered tightly — the test was very difficult","B. Scores are SPREAD OUT and most are above average — the test was both easy and highly varied","C. Most scores are HIGH (negatively skewed = easy test) AND tightly clustered near the top (leptokurtic = little variation). The test may be too easy for this group","D. The distribution is normal with no meaningful interpretation"],a:"C",e:"NEGATIVELY SKEWED = most scores HIGH (test was easy). LEPTOKURTIC = scores TIGHTLY CLUSTERED (very high peak). Combined = most students scored high AND scores are concentrated in a narrow high-score range. Test may be TOO EASY — not discriminating well."},
  {id:"aol-180",d:"difficult",t:"Integrated Assessment",q:"A school administrator reviews assessment data across 6 classrooms. Classroom A shows large SD, Classroom B shows negatively skewed distribution, Classroom C has DI=0.80 on most items, and Classroom D shows most items with D=-0.20. What is the CORRECT interpretation for each classroom?",c:["A. A: Homogeneous; B: Test was difficult; C: Tests are good; D: Tests discriminate well","B. A: HETEROGENEOUS group (wide score spread); B: Test was EASY (most scores high); C: Tests are TOO EASY (should revise/discard); D: Items are NEGATIVELY DISCRIMINATING (problematic — lower group performing better)","C. A: Homogeneous; B: Normal distribution; C: Right difficulty; D: Good discrimination","D. All classrooms show optimal assessment practices"],a:"B",e:"A: Large SD = HETEROGENEOUS (dispersed scores). B: Negatively skewed = test was EASY (most scores high). C: DI=0.80 = TOO EASY (>0.75 = revise/discard). D: D=-0.20 = NEGATIVE DISCRIMINATION (lower group better = item flaw = discard)."},
  {id:"aol-181",d:"difficult",t:"Portfolio Advanced",q:"A teacher argues that the REFLECTION PAPER is the MOST IMPORTANT piece of evidence in a portfolio. What is the STRONGEST EDUCATIONAL JUSTIFICATION for this claim?",c:["A. Reflection papers are the easiest to grade with a rubric","B. Reflection papers directly show the student's thinking, metacognitive awareness, and ability to evaluate their own growth — the PURPOSE of portfolio = self-assessment","C. Reflection papers replace all other portfolio evidence","D. Reflection papers are required by DepEd regardless of content"],a:"B",e:"REFLECTION PAPER is the most important because it directly shows METACOGNITION — the student's awareness of their own learning process and growth. Portfolio is meant to develop self-directed learning; reflection IS the mechanism of that self-direction."},
  {id:"aol-182",d:"difficult",t:"Assessment Advanced Concepts",q:"'The test consistently measures something, but not the intended learning outcome.' This best describes a test that is:",c:["A. Valid but not Reliable","B. Neither Valid nor Reliable","C. Reliable but not Valid — consistent measurement of the WRONG construct","D. Valid and Reliable — consistency is proof of validity"],a:"C",e:"RELIABLE (consistent = always measures the same thing) but NOT VALID (what it measures is NOT the intended learning outcome = wrong construct). This is the classic 'measures something, just not the right thing' reliability-without-validity problem."},
  {id:"aol-183",d:"difficult",t:"Assessment Statistics",q:"A teacher wants to compare how two students performed ACROSS DIFFERENT SUBJECTS with different means and standard deviations. What statistical measure should she use?",c:["A. Raw scores — compare who got the higher number","B. Percentile Ranks — compare who surpassed more classmates","C. Z-Scores or T-Scores — standardize performance so comparisons across different distributions are meaningful","D. Mode — which score occurs most in each subject"],a:"C",e:"Z-SCORES (or T-SCORES) standardize performance relative to each distribution's mean and SD. They allow MEANINGFUL COMPARISON of performance ACROSS DIFFERENT SUBJECTS by expressing each score in the same unit (standard deviations from the mean)."},
  {id:"aol-184",d:"difficult",t:"Reliability Advanced",q:"A researcher claims: 'A test-retest correlation of 0.95 proves both reliability AND validity.' A psychometrician disagrees. The CORRECT position is:",c:["A. The researcher is correct — 0.95 is high enough to guarantee validity","B. The psychometrician is correct — high test-retest reliability proves CONSISTENCY (stability) but does NOT prove the test measures the INTENDED CONSTRUCT (validity)","C. Both are correct — 0.95 correlation proves everything about assessment quality","D. The researcher is correct — reliability is the same as validity in high-stakes testing"],a:"B",e:"HIGH RELIABILITY (0.95 stability) proves CONSISTENCY but does NOT prove VALIDITY. The scale may consistently measure something but not the INTENDED construct. VALIDITY (measuring what you intend) is separate from RELIABILITY (consistency). Reliability is necessary but not sufficient for validity."},
  {id:"aol-185",d:"difficult",t:"Assessment Integration",q:"A student's overall assessment involves: Written Test (Diagnostic at start), Portfolio (collected throughout), Group Performance Task (scored with analytic rubric), and Final Exam (summative). Which Assessment Framework BEST describes this comprehensive approach?",c:["A. Traditional Assessment only — multiple formats but all testing the same construct","B. Assessment OF Learning only — all four are summative in nature","C. An INTEGRATED assessment system addressing FOR Learning (diagnostic, formative elements in portfolio), AS Learning (portfolio self-reflection), and OF Learning (final exam) using both traditional and authentic methods (Principle 3: Balanced)","D. Assessment AS Learning only — all four require student self-direction"],a:"C",e:"This is a COMPREHENSIVE, INTEGRATED assessment system: Diagnostic test = FOR Learning. Portfolio = FOR and AS Learning. Performance task = authentic. Final exam = OF Learning. Together = Balanced (Principle 3) coverage of all purposes and modes."},
  {id:"aol-186",d:"difficult",t:"Percentile and Normal Distribution",q:"A student's Z-score is +2. What is the APPROXIMATE PERCENTILE RANK, and what STANINE does this correspond to?",c:["A. About 50th percentile; Stanine 5","B. About 84th percentile; Stanine 7","C. About 97.72nd percentile; Stanine 9","D. About 99.86th percentile; Stanine 9"],a:"C",e:"Z=+2 = 2 SD above mean. Below +2 SD = 50% + 47.72% = 97.72nd percentile. STANINE 9 = Very High (top of the distribution). A student at the 97.72nd percentile is clearly in Stanine 9 (Very High)."},
  {id:"aol-187",d:"difficult",t:"Criterion-related Validity Advanced",q:"A school uses a reading readiness test to decide which Kindergartners should receive early intervention. They validated the test by correlating readiness scores with reading achievement at the END of Grade 1. This validity evidence is:",c:["A. Concurrent Validity — correlating two measures at the same time","B. Face Validity — the test looks like it measures readiness","C. Content Validity — covering all reading readiness skills","D. Predictive Validity — correlating readiness scores (early) with future reading achievement (end of Grade 1)"],a:"D",e:"PREDICTIVE VALIDITY — correlating scores from an early measure (Kindergarten readiness test) with a FUTURE performance measure (Grade 1 reading achievement at the end of the year) = predicting future performance."},
  {id:"aol-188",d:"difficult",t:"Assessment Design Critique",q:"A 100-item true-false test covering only 2 of 10 learning objectives has items with consistently high DI (0.80+) and low D (0.10). What are the THREE MAIN assessment problems with this test?",c:["A. Only validity is a problem — the test measures the wrong things","B. Only reliability is a problem — inconsistent scores","C. THREE problems: (1) Content Validity violated (only 2/10 objectives covered), (2) Items too EASY (DI=0.80 = revise/discard), (3) Items NON-DISCRIMINATING (D=0.10 = revise) — the test fails Principles 2, 4, and item quality criteria","D. No problems — high DI means students learned well"],a:"C",e:"THREE PROBLEMS: (1) CONTENT VALIDITY — only 2 of 10 objectives = not representative (Principle 4). (2) ITEMS TOO EASY — DI=0.80 = above 0.75 = revise or discard. (3) NON-DISCRIMINATING — D=0.10 = below 0.20 = revise. Comprehensive failure of assessment quality."},
  {id:"aol-189",d:"difficult",t:"Summative Assessment and Reform",q:"Summative Assessment results showing consistently low performance across ALL SCHOOLS in a province could pave the way for educational reforms at which level?",c:["A. Only classroom level — teachers should change their instruction","B. Only student level — students should study harder","C. Potentially at MULTIPLE LEVELS — classroom instruction, school curriculum, district resource allocation, and even national policy reform — assessment results as a driver of systemic change","D. Only administrative level — school administrators should change hiring practices"],a:"C",e:"Summative Assessment is 'a powerful factor that could PAVE THE WAY FOR EDUCATIONAL REFORMS' — province-wide consistently low results could trigger reform at classroom (instruction), school (curriculum), district (resources), and national (policy) levels."},
  {id:"aol-190",d:"difficult",t:"Discrimination Index and Test Quality",q:"A teacher designs a test where ALL items have D = 1.0 (perfect discrimination). What can she CORRECTLY conclude about this test?",c:["A. The test is perfect — maximum discrimination is always the goal","B. Every item perfectly separates high and low performers — but this does NOT mean the test is valid (measures the right content) or balanced","C. The test is both valid and reliable — high discrimination proves both","D. Items with D=1.0 are always too difficult — they should all be discarded"],a:"B",e:"D=1.0 (perfect discrimination) means the test perfectly distinguishes high from low performers. HOWEVER, this does NOT mean: (1) the test is content valid (covers all objectives), (2) the test is balanced (all domains), or (3) the items are appropriate difficulty. Discrimination ≠ Validity."},
  {id:"aol-191",d:"difficult",t:"Integrated Concepts",q:"A teacher argues: 'I use only Summative Assessment because formative assessment takes too much class time.' A curriculum specialist responds: 'This violates multiple assessment principles.' Which principles are VIOLATED?",c:["A. Only Principle 4 (Validity) — the test doesn't measure the right thing","B. Only Principle 5 (Reliability) — scores will be inconsistent","C. MULTIPLE PRINCIPLES: Principle 3 (Balance — no formative means no FOR and AS Learning), Assessment FOR Learning principle (no formative, no diagnostic), and Missing the formative feedback cycle that improves instruction during instruction","D. No principles violated — summative is the most important type"],a:"C",e:"MULTIPLE VIOLATIONS: (1) Balance (Principle 3) — no formative/diagnostic = unbalanced. (2) Assessment FOR Learning — Formative Assessment is core to FOR Learning (monitoring, feedback, improvement during instruction). (3) No feedback cycle = missed opportunity to ensure learning takes place."},
  {id:"aol-192",d:"difficult",t:"Z-Score T-Score Integration",q:"A student's T-score is 35. What is the Z-score, and what does this tell you about the student's performance?",c:["A. Z = +1.5; student is above average","B. Z = 0.0; student is at the mean","C. Z = -1.5; student is 1.5 standard deviations BELOW the mean","D. Z = -3.5; student is far below average"],a:"C",e:"T = 10z + 50 → 35 = 10z + 50 → 10z = -15 → z = -1.5. Student is 1.5 STANDARD DEVIATIONS BELOW THE MEAN. T=50 = mean, T=35 = 1.5 SD below mean = Below Average performance."},
  {id:"aol-193",d:"difficult",t:"Assessment Research",q:"Research shows that FORMATIVE ASSESSMENT with immediate, specific feedback produces LARGER LEARNING GAINS than summative-only assessment. The BEST explanation for this finding is:",c:["A. Formative assessment tests students more frequently, increasing test practice effects","B. Formative assessment provides FEEDBACK DURING INSTRUCTION that allows both teachers to adjust teaching AND students to adjust learning — closing the gap between current performance and learning goals before it is too late","C. Summative assessment is less accurate than formative assessment","D. Students perform better when they know they are being observed"],a:"B",e:"Formative Assessment's power lies in its IMMEDIATE, SPECIFIC FEEDBACK LOOP during instruction. Teachers can adjust TEACHING; students can adjust LEARNING — before the summative assessment. This ongoing adjustment closes learning gaps while there is still time to act."},
  {id:"aol-194",d:"difficult",t:"Test Construction Integration",q:"A teacher receives this student complaint: 'The True-False section gave you the answer to two Multiple Choice questions in the same test!' The teacher has violated which test construction rules from BOTH sections?",c:["A. True-False Rule #3 (Long sentences) and Multiple Choice Rule #1 (Unfamiliar words)","B. No rules violated — item interaction is allowed","C. True-False Rule #5 (Verbatim from textbook) and Multiple Choice Rule #2 (Vague modifiers)","D. Multiple Choice Rule #6 (Stems that REVEAL answers to other items) AND this creates Cross-item cuing — a validity threat across test sections"],a:"D",e:"Multiple Choice RULE #6 — Avoid stems that reveal the answer to another item. When True-False content gives away MC answers = CROSS-ITEM CUING = major validity threat. Students answer correctly based on test design rather than knowledge."},
  {id:"aol-195",d:"difficult",t:"Assessment Equity",q:"A student from a rural area with limited internet access performs poorly on an Authentic Assessment that requires online research and a digital product. A teacher argues this is valid because authentic assessment uses 'real-world tasks.' A curriculum specialist argues this assessment is inequitable. The MOST DEFENSIBLE position is:",c:["A. The teacher is correct — authentic assessment always reflects real-world demands","B. The specialist is correct — a valid assessment must be APPROPRIATE FOR THE CONTEXT AND STUDENTS (Principle 2: Appropriate Assessment Methods). Tasks that disadvantage students due to resource access rather than knowledge violate validity","C. Neither is correct — all assessment is inherently biased","D. Students who can't access technology should be exempt from authentic assessment"],a:"B",e:"PRINCIPLE 2 (APPROPRIATE ASSESSMENT METHODS) — assessment methods must be appropriate for the students and context. A digital task that disadvantages resource-limited students violates VALIDITY — it measures RESOURCE ACCESS, not the intended learning outcome."},
  {id:"aol-196",d:"difficult",t:"Normal Distribution Advanced",q:"In a normal distribution, the percentage of scores falling between +1 SD and +2 SD (ABOVE the mean) is approximately:",c:["A. 34.13%","B. 13.59%","C. 2.14%","D. 47.72%"],a:"B",e:"From the normal distribution: 0 to +1 SD = 34.13%. 0 to +2 SD = 47.72%. Therefore, +1 SD to +2 SD = 47.72% - 34.13% = 13.59%."},
  {id:"aol-197",d:"difficult",t:"Assessment Philosophy",q:"A teacher argues: 'Testing is an act of LEARNING, not just measuring.' This view is MOST consistent with which assessment framework?",c:["A. Assessment OF Learning — using grades to certify achievement","B. Assessment FOR Learning — using data to improve instruction","C. Assessment AS Learning — the act of assessment is itself a learning experience that promotes metacognition and self-regulation","D. Traditional Assessment — objective tests are the best measure of knowledge"],a:"C",e:"Assessment AS Learning — the act of assessing IS a form of learning. Students who engage with rubrics, self-assess, reflect on their portfolios, and evaluate their own work are LEARNING THROUGH ASSESSMENT. 'Testing is learning' = AS Learning philosophy."},
  {id:"aol-198",d:"difficult",t:"Item Difficulty Advanced",q:"A teacher wants items that will provide MAXIMUM DISCRIMINATION between high and low performers. Research suggests the OPTIMAL Difficulty Index for maximum discrimination is approximately:",c:["A. 0.00 — very difficult items discriminate best","B. 0.50 — items at 50% correct provide the widest spread between high and low performers","C. 0.75 — easy items are best for discrimination","D. 1.00 — everyone answers correctly, maximizing discrimination"],a:"B",e:"Items with DI ≈ 0.50 (50% correct) provide MAXIMUM DISCRIMINATION because they split the group evenly — 50% right = maximum opportunity for the discrimination index to show differences between high and low performers."},
  {id:"aol-199",d:"difficult",t:"Assessment Systems",q:"The sequence: 1983 NESC → 1989 NSEC → 2002 BEC → 2010 RBEC → K-12 Curriculum (RA 10533) represents the evolution of the Philippine curriculum. At each transition, assessment systems also changed. The K-12 GRADING SYSTEM (DepEd Order 8) represents which type of educational reform driven by assessment?",c:["A. A minor administrative change with no educational significance","B. A MAJOR SYSTEMIC REFORM — changing from component-free grading to a three-component grading system (Written Works, Performance Tasks, Quarterly Assessment) that balances traditional and authentic assessment across all domains","C. A change driven purely by political decisions with no pedagogical basis","D. A temporary pilot program with no lasting impact"],a:"B",e:"The K-12 Grading System (DepEd Order 8) is a MAJOR SYSTEMIC REFORM — introducing a THREE-COMPONENT system that explicitly BALANCES Written Works (traditional), Performance Tasks (authentic), and Quarterly Assessment across all subject areas and grade levels."},
  {id:"aol-200",d:"difficult",t:"Comprehensive Assessment Philosophy",q:"The COMPLETE ASSESSMENT CYCLE of a teacher who uses all five types of assessment (Placement → Diagnostic → Formative → Summative → Self-Assessment) BEST reflects which overarching assessment philosophy?",c:["A. Assessment OF Learning — grades are the ultimate goal","B. Traditional Assessment — objective tests are most important","C. A HOLISTIC ASSESSMENT ECOSYSTEM — integrating FOR Learning (placement, diagnostic, formative), OF Learning (summative), and AS Learning (self-assessment) in a continuous, interconnected cycle that serves LEARNING FIRST and grading second","D. Authentic Assessment — all five types require real-world tasks"],a:"C",e:"A complete assessment cycle using all five types creates a HOLISTIC ECOSYSTEM: FOR Learning (support instruction), AS Learning (develop self-regulation), OF Learning (certify achievement). LEARNING IS THE PRIMARY PURPOSE — assessment serves learning, not just grading or ranking."},
];
